    {
      name: 'list_tools_by_category',
      description: '按分类列出轻量工具清单。只返回工具名、简介、标签、适用场景和风险等级，不返回参数 schema。',
      input_schema: {
        type: 'object',
        properties: {
          category: {
            type: 'string',
            enum: TOOL_CATEGORY_INFOS.map((category) => category.name),
            description: '能力分类名称',
          },
        },
        required: ['category'],
      },
    },
    {
      name: 'get_tool_detail',
      description: '按工具名获取完整工具用法，包括参数定义、输入输出、示例、约束和注意事项。',
      input_schema: {
        type: 'object',
        properties: {
          tool_name: { type: 'string', description: '工具名，必须来自 list_tools_by_category 返回结果。' },
        },
        required: ['tool_name'],
      },
    },
    {
      name: 'execute_tool',
      description: '执行已通过 get_tool_detail 查看过详情的业务工具。只有参数完整且风险可接受时才调用。',
      input_schema: {
        type: 'object',
        properties: {
          tool_name: { type: 'string', description: '要执行的业务工具名。' },
          args: {
            type: 'object',
            description: '业务工具参数，必须符合 get_tool_detail 返回的 input_schema。',
            properties: {},
          },
        },
        required: ['tool_name'],
      },
    },
  ]
}

export function isDiscoveryToolName(name: string): boolean {
  return (DISCOVERY_TOOL_NAMES as readonly string[]).includes(name)
}

export function isToolCategoryName(name: string): name is ToolCategoryName {
  return TOOL_CATEGORY_INFOS.some((category) => category.name === name)
}

export function isBrowserBusinessToolName(name: string): boolean {
  return BROWSER_TOOL_LIST.some((tool) => tool.name === name)
}

export function buildCategoryListResponse(): ToolDiscoveryResponse<{ categories: ToolCategoryInfo[] }> {
  return {
    stage: 'category_list',
    need_next: true,
    next_action: 'select_category',
    data: {
      categories: TOOL_CATEGORY_INFOS,
    },
    message: '请先根据任务选择能力分类。',
  }
}

export function buildToolListResponse(
  category: string,
  enabledToolNames?: EnabledToolFilter,
): ToolDiscoveryResponse<{
  category: string
  tools: Array<{
    name: string
    summary: string
    tags: string[]
    suitable_for: string[]
    risk_level: ToolRiskLevel
  }>
}> {
  if (!isToolCategoryName(category)) {
    return {
      stage: 'tool_list',
      need_next: true,
      next_action: 'select_category',
      data: { category, tools: [] },
      message: `未知能力分类：${category}。请先调用 list_categories 查看可用分类。`,
    }
  }

  const tools = BROWSER_TOOL_LIST
    .filter((tool) => tool.discoveryCategory === category && isToolEnabled(tool.name, enabledToolNames))
    .map((tool) => ({
      name: tool.name,
      summary: tool.description,
      tags: tool.tags,
      suitable_for: tool.suitableFor,
      risk_level: tool.riskLevel,
    }))

  return {
    stage: 'tool_list',
    need_next: tools.length > 0,
    next_action: tools.length > 0 ? 'select_tool' : 'select_category',
    data: {
      category,
      tools,
    },
    message: tools.length > 0
      ? '请从工具列表中选择工具；需要参数时继续调用 get_tool_detail。'
      : '当前分类没有可用工具，或工具已被禁用。',
  }
}

export function buildToolDetailResponse(
  toolName: string,
  enabledToolNames?: EnabledToolFilter,
): ToolDiscoveryResponse<Record<string, unknown>> {
  const meta = BROWSER_TOOL_LIST.find((tool) => tool.name === toolName)
  const definition = createBrowserTools(null).find((tool) => tool.name === toolName)

  if (!meta || !definition) {
    return {
      stage: 'tool_detail',
      need_next: true,
      next_action: 'select_tool',
      data: {},
      message: `未知工具：${toolName}。请先调用 list_tools_by_category 查看可用工具。`,
    }
  }

  if (!isToolEnabled(toolName, enabledToolNames)) {
    return {
      stage: 'tool_detail',
      need_next: true,
      next_action: 'select_tool',
      data: {},
      message: `工具 ${toolName} 当前未启用，不能查看详情或执行。`,
    }
  }

  return {
    stage: 'tool_detail',
    need_next: true,
    next_action: 'execute',
    data: {
      name: definition.name,
      category: meta.discoveryCategory,
      description: definition.description,
      input_schema: definition.input_schema,
      output_schema: GENERIC_OUTPUT_SCHEMA,
      examples: [
        {
          input: TOOL_EXAMPLE_INPUTS[toolName] ?? {},
          output: { success: true, result: {} },
        },
      ],
      constraints: buildToolConstraints(meta, definition),
      notes: buildToolNotes(meta),
    },
    message: '请根据 input_schema 提供完整参数后调用 execute_tool。',
  }
}

function isToolEnabled(name: string, enabledToolNames?: EnabledToolFilter): boolean {
  if (!enabledToolNames) return true
  return Array.isArray(enabledToolNames)
    ? enabledToolNames.includes(name)
    : enabledToolNames.has(name)
}

function buildToolConstraints(meta: ToolMeta, definition: ToolDefinition): string[] {
  const constraints = ['参数必须符合 input_schema。']

  if (definition.input_schema.required?.length) {
    constraints.push(`必填参数：${definition.input_schema.required.join(', ')}。`)
  }
  if (meta.riskLevel === 'high') {
    constraints.push('高风险工具，执行前必须确认目标明确且用户意图清晰。')
  }
  if (meta.discoveryCategory === 'dom') {
    constraints.push('CSS 选择器应尽量唯一定位目标元素。')
  }
  if (meta.discoveryCategory === 'tab') {
    constraints.push('涉及指定标签页时，应优先确认 tabId。')
  }

  return constraints
}

function buildToolNotes(meta: ToolMeta): string[] {
  const notes = [`风险等级：${meta.riskLevel}。`]

  if (meta.riskLevel !== 'low') {
    notes.push('如果参数不足，不要猜测执行，应先获取更多上下文或追问用户。')
  }
  if (meta.name === 'close_tab') {
    notes.push('关闭标签页属于破坏性操作，应在用户明确要求时执行。')
  }
  if (meta.name === 'get_page_screenshot') {
    notes.push('截图结果可能以图片内容返回。')
  }
  if (meta.name === 'create_tab') {
    notes.push('当前执行层对创建标签页可能返回 not yet supported 提示。')
  }

  return notes
}

import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import type { Bookmark, BookmarkFolder } from '../types'

const api = window.api

export const useBookmarkStore = defineStore('bookmark', () => {
  // ====== 状态 ======
  const folders = ref<BookmarkFolder[]>([])
  const bookmarks = ref<Bookmark[]>([])

  // ====== 计算属性 ======

  /** 根级文件夹 */
  const rootFolders = computed(() =>
    folders.value.filter((f) => f.parentId === null).sort((a, b) => a.order - b.order)
  )

  /** 书签栏统一列表：所有根级文件夹（第一层），点击展开查看内部书签和子文件夹 */
  const toolbarItems = computed(() =>
    rootFolders.value.map((f) => ({ type: 'folder' as const, data: f, order: f.order }))
  )

  // ====== 文件夹操作 ======

  async function loadFolders() {
    folders.value = await api.bookmarkFolder.list()
  }

  async function createFolder(data: Omit<BookmarkFolder, 'id'>) {
    const folder = await api.bookmarkFolder.create(data)
    folders.value.push(folder)
    return folder
  }

  async function updateFolder(id: string, data: Partial<Omit<BookmarkFolder, 'id'>>) {
    await api.bookmarkFolder.update(id, data)
    const idx = folders.value.findIndex((f) => f.id === id)
    if (idx !== -1) folders.value[idx] = { ...folders.value[idx], ...data }
  }

  async function deleteFolder(id: string) {
    await api.bookmarkFolder.delete(id)
    folders.value = folders.value.filter((f) => f.id !== id)
    // 级联删除相关书签
    bookmarks.value = bookmarks.value.filter((b) => b.folderId !== id)
  }

  /** 删除所有空文件夹（无书签且无子文件夹），返回被删除的文件夹 ID */
  async function deleteEmptyFolders(): Promise<string[]> {
    const deletedIds = await api.bookmarkFolder.deleteEmpty()
    if (deletedIds.length > 0) {
      const idSet = new Set(deletedIds)
      folders.value = folders.value.filter((f) => !idSet.has(f.id))
    }
    return deletedIds
  }

  async function reorderFolders(ids: string[]) {
    await api.bookmarkFolder.reorder(ids)
    ids.forEach((id, order) => {
      const f = folders.value.find((f) => f.id === id)
      if (f) f.order = order
    })
  }

  /** 获取指定文件夹的子文件夹 */
  function getChildFolders(parentId: string): BookmarkFolder[] {
    return folders.value.filter((f) => f.parentId === parentId).sort((a, b) => a.order - b.order)
  }

  // ====== 书签操作 ======

  async function loadBookmarks() {
    bookmarks.value = await api.bookmark.list()
  }

  async function createBookmark(data: Omit<Bookmark, 'id'>) {
    const bookmark = await api.bookmark.create(data)
    bookmarks.value.push(bookmark)
    return bookmark
  }

  async function updateBookmark(id: string, data: Partial<Omit<Bookmark, 'id'>>) {
    await api.bookmark.update(id, data)
    const idx = bookmarks.value.findIndex((b) => b.id === id)
    if (idx !== -1) bookmarks.value[idx] = { ...bookmarks.value[idx], ...data }
  }

  async function deleteBookmark(id: string) {
    await api.bookmark.delete(id)
    bookmarks.value = bookmarks.value.filter((b) => b.id !== id)
  }

  async function batchDeleteBookmarks(ids: string[]) {
    await api.bookmark.batchDelete(ids)
    const idSet = new Set(ids)
    bookmarks.value = bookmarks.value.filter((b) => !idSet.has(b.id))
  }

  async function reorderBookmarks(ids: string[]) {
    await api.bookmark.reorder(ids)
    ids.forEach((id, order) => {
      const b = bookmarks.value.find((b) => b.id === id)
      if (b) b.order = order
    })
  }

  /** 获取指定文件夹的书签 */
  function getBookmarksByFolder(folderId: string): Bookmark[] {
    return bookmarks.value.filter((b) => b.folderId === folderId).sort((a, b) => a.order - b.order)
  }

  /** 检查 URL 是否已收藏 */
  function isBookmarked(url: string): boolean {
    return bookmarks.value.some((b) => b.url === url)
  }

  /** 查找 URL 对应的书签 */
  function findBookmarkByUrl(url: string): Bookmark | undefined {
    return bookmarks.value.find((b) => b.url === url)
  }

  // ====== 移动操作 ======

  /** 移动文件夹到新的父级下指定位置 */
  async function moveFolder(folderId: string, targetParentId: string | null, targetIndex: number) {
    const folder = folders.value.find((f) => f.id === folderId)
    if (!folder) return

    const oldParentId = folder.parentId

    // 如果同父级下移动，直接重排
    if (oldParentId === targetParentId) {
      const siblings = getChildFolders(oldParentId)
      const reordered = siblings.filter((f) => f.id !== folderId)
      reordered.splice(targetIndex, 0, folder)
      await reorderFolders(reordered.map((f) => f.id))
      return
    }

    // 跨父级移动：先更新 parentId
    await updateFolder(folderId, { parentId: targetParentId })

    // 在旧父级下重排剩余子项
    const oldSiblings = getChildFolders(oldParentId)
    if (oldSiblings.length > 0) {
      await reorderFolders(oldSiblings.map((f) => f.id))
    }

    // 在新父级下插入并重排
    const newSiblings = getChildFolders(targetParentId)
    const reordered = newSiblings.filter((f) => f.id !== folderId)
    reordered.splice(targetIndex, 0, folder)
    await reorderFolders(reordered.map((f) => f.id))
  }

  /** 移动书签到新文件夹下指定位置 */
  async function moveBookmark(bookmarkId: string, targetFolderId: string, targetIndex: number) {
    const bookmark = bookmarks.value.find((b) => b.id === bookmarkId)
    if (!bookmark) return

    const oldFolderId = bookmark.folderId

    // 如果同文件夹下移动，直接重排
    if (oldFolderId === targetFolderId) {
      const siblings = getBookmarksByFolder(oldFolderId)
      const reordered = siblings.filter((b) => b.id !== bookmarkId)
      reordered.splice(targetIndex, 0, bookmark)
      await reorderBookmarks(reordered.map((b) => b.id))
      return
    }

    // 跨文件夹移动：先更新 folderId
    await updateBookmark(bookmarkId, { folderId: targetFolderId })

    // 在旧文件夹下重排剩余书签
    const oldSiblings = getBookmarksByFolder(oldFolderId)
    if (oldSiblings.length > 0) {
      await reorderBookmarks(oldSiblings.map((b) => b.id))
    }

    // 在新文件夹下插入并重排
    const newSiblings = getBookmarksByFolder(targetFolderId)
    const reordered = newSiblings.filter((b) => b.id !== bookmarkId)
    reordered.splice(targetIndex, 0, bookmark)
    await reorderBookmarks(reordered.map((b) => b.id))
  }

  // ====== 导入导出 ======

  /** 解析 Chrome/Netscape 书签 HTML，返回待创建的文件夹和书签 */
  function parseBookmarkHTML(html: string): {
    folders: Omit<BookmarkFolder, 'id'>[]
    bookmarks: Omit<Bookmark, 'id'>[]
  } {
    const parser = new DOMParser()
    const doc = parser.parseFromString(html, 'text/html')
    const rootDL = doc.querySelector('DL')
    if (!rootDL) return { folders: [], bookmarks: [] }

    const pendingFolders: Omit<BookmarkFolder, 'id'>[] = []
    const pendingBookmarks: Omit<Bookmark, 'id'>[] = []
    // Chrome 文件夹名 → SessionBox folderId 的映射
    const chromeFolderMap = new Map<string, string>()

    function walk(dl: Element, parentFolderId: string | null, folderOrder: { value: number }) {
      const dts = dl.querySelectorAll(':scope > DT')
      for (const dt of dts) {
        const h3 = dt.querySelector(':scope > H3')
        if (h3) {
          // 这是一个文件夹
          const folderName = h3.textContent?.trim() || '未命名文件夹'
          const existingFolder = folders.value.find(
            (f) => f.name === folderName && f.parentId === parentFolderId
          )
          if (existingFolder) {
            chromeFolderMap.set(h3.textContent ?? folderName, existingFolder.id)
          } else {
            const folderData: Omit<BookmarkFolder, 'id'> = {
              name: folderName,
              parentId: parentFolderId,
              order: folderOrder.value++
            }
            pendingFolders.push(folderData)
            // 用临时 key 映射，后续 batchCreate 后更新
            chromeFolderMap.set(h3.textContent ?? folderName, `__pending_${pendingFolders.length}`)
          }

          // 处理子 DL
          const childDL = dt.querySelector(':scope > DL')
          if (childDL) {
            walk(childDL, chromeFolderMap.get(h3.textContent ?? folderName)!, { value: 0 })
          }
          continue
        }

        const a = dt.querySelector(':scope > A')
        if (a) {
          const url = a.getAttribute('HREF') || ''
          const title = a.textContent?.trim() || url
          if (!url || url.startsWith('javascript:') || url.startsWith('place:')) continue
          // 同文件夹下 URL 去重
          if (bookmarks.value.some((b) => b.url === url && b.folderId === parentFolderId)) continue
          if (pendingBookmarks.some((b) => b.url === url && b.folderId === parentFolderId)) continue

          pendingBookmarks.push({
            title,
            url,
            folderId: parentFolderId,
            order: pendingBookmarks.filter((b) => b.folderId === parentFolderId).length
          })
        }
      }
    }

    walk(rootDL, null, { value: 0 })
    return { folders: pendingFolders, bookmarks: pendingBookmarks }
  }

  /** 导入 Chrome 书签 HTML 文件 */
  async function importBookmarks(): Promise<{ folderCount: number; bookmarkCount: number }> {
    const result = await api.bookmark.importOpenFile()
    if (!result) return { folderCount: 0, bookmarkCount: 0 }

    const { folders: pendingFolders, bookmarks: pendingBookmarks } = parseBookmarkHTML(result.html)
    if (pendingFolders.length === 0 && pendingBookmarks.length === 0) {
      return { folderCount: 0, bookmarkCount: 0 }
    }

    // 先批量创建文件夹，建立 ID 映射
    let folderIndex = 0
    const pendingFolderOldMap = new Map<number, string>()
    for (const f of pendingFolders) {
      folderIndex++
      pendingFolderOldMap.set(folderIndex, f.parentId || '__root__')
    }

    const created = await api.bookmark.batchCreate({ folders: pendingFolders, bookmarks: [] })

    // 建立新文件夹 ID 映射，处理父子关系
    // pendingFolderOldMap 存储了 __pending_N → 父 ID 的关系
    // 但 batchCreate 时 parentId 可能是 __pending_N 需要替换
    const pendingIdMap = new Map<string, string>()
    for (let i = 0; i < created.folders.length; i++) {
      pendingIdMap.set(`__pending_${i + 1}`, created.folders[i].id)
    }

    // 更新待创建书签的 folderId（将 __pending_ 替换为真实 ID）
    const fixedBookmarks: Omit<Bookmark, 'id'>[] = pendingBookmarks.map((b) => ({
      ...b,
      folderId: pendingIdMap.get(b.folderId) || b.folderId
    }))

    // 更新文件夹的父子关系（batchCreate 创建的文件夹 parentId 可能仍是 __pending_）
    for (const createdFolder of created.folders) {
      if (createdFolder.parentId?.startsWith('__pending_')) {
        const realParentId = pendingIdMap.get(createdFolder.parentId)
        if (realParentId) {
          await api.bookmarkFolder.update(createdFolder.id, { parentId: realParentId })
          createdFolder.parentId = realParentId
        }
      }
    }

    // 再批量创建书签
    const bookmarkResult = await api.bookmark.batchCreate({ folders: [], bookmarks: fixedBookmarks })

    // 更新本地状态
    folders.value.push(...created.folders)
    bookmarks.value.push(...bookmarkResult.bookmarks)

    return { folderCount: created.folders.length, bookmarkCount: bookmarkResult.bookmarks.length }
  }

  /** 生成 Netscape 书签 HTML */
  function generateBookmarkHTML(): string {
    const lines: string[] = [
      '<!DOCTYPE NETSCAPE-Bookmark-file-1>',
      '<!-- This is an automatically generated file.',
      '     It will be read and overwritten.',
      '     DO NOT EDIT! -->',
      '<META HTTP-EQUIV="Content-Type" CONTENT="text/html; charset=UTF-8">',
      '<TITLE>Bookmarks</TITLE>',
      '<H1>Bookmarks</H1>',
      '<DL><p>'
    ]

    const rootItems = folders.value
      .filter((f) => f.parentId === null)
      .sort((a, b) => a.order - b.order)

    for (const rootFolder of rootItems) {
      renderFolder(rootFolder, lines, 1)
    }

    // 根级无文件夹的书签（理论上不存在，但兜底）
    const rootBookmarks = bookmarks.value
      .filter((b) => !folders.value.some((f) => f.id === b.folderId))
      .sort((a, b) => a.order - b.order)
    for (const bm of rootBookmarks) {
      lines.push(`        <DT><A HREF="${escapeAttr(bm.url)}">${escapeText(bm.title)}</A>`)
    }

    lines.push('</DL><p>')
    return lines.join('\n')
  }

  function renderFolder(folder: BookmarkFolder, lines: string[], depth: number) {
    const indent = '    '.repeat(depth)
    lines.push(`${indent}<DT><H3>${escapeText(folder.name)}</H3>`)
    lines.push(`${indent}<DL><p>`)

    const childFolders = folders.value
      .filter((f) => f.parentId === folder.id)
      .sort((a, b) => a.order - b.order)

    const childBookmarks = bookmarks.value
      .filter((b) => b.folderId === folder.id)
      .sort((a, b) => a.order - b.order)

    for (const child of childFolders) {
      renderFolder(child, lines, depth + 1)
    }

    for (const bm of childBookmarks) {
      lines.push(
        `${indent}    <DT><A HREF="${escapeAttr(bm.url)}">${escapeText(bm.title)}</A>`
      )
    }

    lines.push(`${indent}</DL><p>`)
  }

  function escapeAttr(str: string): string {
    return str.replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  }

  function escapeText(str: string): string {
    return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  }

  /** 导出所有书签到 HTML 文件 */
  async function exportBookmarks(): Promise<boolean> {
    const html = generateBookmarkHTML()
    const result = await api.bookmark.exportSaveFile(html)
    return result.success
  }

  // ====== 初始化 ======

  async function init() {
    await Promise.all([loadFolders(), loadBookmarks()])
  }

  return {
    folders,
    bookmarks,
    toolbarItems,
    rootFolders,
    loadFolders,
    createFolder,
    updateFolder,
    deleteFolder,
    deleteEmptyFolders,
    reorderFolders,
    getChildFolders,
    loadBookmarks,
    createBookmark,
    updateBookmark,
    deleteBookmark,
    batchDeleteBookmarks,
    reorderBookmarks,
    moveFolder,
    moveBookmark,
    getBookmarksByFolder,
    isBookmarked,
    findBookmarkByUrl,
    importBookmarks,
    exportBookmarks,
    init
  }
})

import { defineStore } from 'pinia'
import { ref, computed, toRaw } from 'vue'
import type { ChatSession, ChatMessage, ToolCall, ChatThinkingBlock } from '@/types'
import {
  createSession as dbCreateSession,
  listSessionsByScope as dbListSessionsByScope,
  deleteSession as dbDeleteSession,
  updateSessionTitle as dbUpdateSessionTitle,
  addMessage as dbAddMessage,
  listMessages as dbListMessages,
  updateMessage as dbUpdateMessage,
  deleteMessage as dbDeleteMessage,
  deleteMessages as dbDeleteMessages,
  clearMessages as dbClearMessages,
} from '@/lib/chat-db'
import { useAIProviderStore } from './ai-provider'
import { useChatUIStore } from './chat-ui'
import { useWorkflowStore } from './workflow'
import { runAgentStream } from '@/lib/agent/agent'

export function createChatStore(scope: string) {
  const storeId = `chat-${scope}`
  return defineStore(storeId, () => {
    const sessions = ref<ChatSession[]>([])
    const currentSessionId = ref<string | null>(null)
    const messages = ref<ChatMessage[]>([])
    const isStreaming = ref(false)

    // 流式输出临时状态
    const streamingToken = ref('')
    const streamingToolCalls = ref<ToolCall[]>([])
    const streamingThinkingBlocks = ref<ChatThinkingBlock[]>([])
    const streamingUsage = ref<{ inputTokens: number; outputTokens: number } | null>(null)
    const retryStatus = ref<{ attempt: number; maxRetries: number; delayMs: number; status: number } | null>(null)
    const abortController = ref<AbortController | null>(null)
    const streamingMessageId = ref<string | null>(null)
    let streamingRenderOrder = 0
    let streamCleanup: (() => void) | null = null
    let currentRequestId: string | null = null

    const currentSession = computed(() =>
      sessions.value.find((s) => s.id === currentSessionId.value) ?? null,
    )

    // ===== 会话管理 =====

    async function loadSessions() {
      sessions.value = await dbListSessionsByScope(scope)
    }

    async function createSession() {
      const providerStore = useAIProviderStore()
      const uiStore = useChatUIStore()
      if (!providerStore.currentProvider || !providerStore.currentModel) {
        throw new Error('请先选择 AI 模型')
      }
      const session = await dbCreateSession(
        scope,
        providerStore.currentModel.id,
        providerStore.currentProvider.id,
        uiStore.targetTabId,
      )
      sessions.value.unshift(session)
      currentSessionId.value = session.id
      messages.value = []
      return session
    }

    async function deleteSessionById(id: string) {
      await dbDeleteSession(id)
      sessions.value = sessions.value.filter((s) => s.id !== id)
      if (currentSessionId.value === id) {
        currentSessionId.value = null
        messages.value = []
      }
    }

    async function switchSession(id: string) {
      currentSessionId.value = id
      messages.value = await dbListMessages(id)
    }

    async function clearSessionMessages(id: string) {
      await dbClearMessages(id)
      if (currentSessionId.value === id) {
        messages.value = []
      }
      const session = sessions.value.find((s) => s.id === id)
      if (session) {
        session.messageCount = 0
      }
    }

    // ===== 消息发送 =====

    async function streamAssistantReply(content: string, images?: string[]) {
      const sessionId = currentSessionId.value!
      const providerStore = useAIProviderStore()
      const uiStore = useChatUIStore()

      const assistantMsg = await dbAddMessage({
        sessionId,
        role: 'assistant',
        content: '',
        createdAt: Date.now(),
        modelId: providerStore.currentModel?.id,
      })
      messages.value.push(assistantMsg)
      streamingMessageId.value = assistantMsg.id

      isStreaming.value = true
      streamingToken.value = ''
      streamingToolCalls.value = []
      streamingThinkingBlocks.value = []
      streamingUsage.value = null
      retryStatus.value = null
      streamingRenderOrder = 0

      try {
        const controller = new AbortController()
        abortController.value = controller

        const history = messages.value
          .filter((m) => m.id !== assistantMsg.id && m.role !== 'system')
          .map((m) => ({
            role: m.role,
            content: m.content,
          }))

        // 工作流模式：注入工作流上下文
        const workflowStore = useWorkflowStore()
        const currentSessionData = sessions.value.find((s) => s.id === currentSessionId.value)
        const isWorkflowMode = !!currentSessionData?.workflowId
        const workflowOptions = isWorkflowMode && workflowStore.currentWorkflow ? {
          mode: 'workflow' as const,
          workflowId: workflowStore.currentWorkflow.id,
          workflowSummary: {
            id: workflowStore.currentWorkflow.id,
            name: workflowStore.currentWorkflow.name,
            description: workflowStore.currentWorkflow.description,
            nodes: workflowStore.currentWorkflow.nodes.map(n => ({ id: n.id, type: n.type, label: n.label })),
            edges: workflowStore.currentWorkflow.edges.map(e => ({ id: e.id, source: e.source, target: e.target })),
          },
        } : undefined

        const result = await runAgentStream(
          history,
          content,
          images,
          {
            onToken: (token: string) => {
              streamingToken.value += token
            },
            onToolCall: (call: ToolCall) => {
              call.textPosition = streamingToken.value.length
              call.renderOrder = streamingRenderOrder++
              streamingToolCalls.value.push(call)
            },
            onToolCallArgs: (event: { toolUseId: string; args: Record<string, unknown> }) => {
              const tc = streamingToolCalls.value.find((t) => t.id === event.toolUseId)
              if (tc) {
                tc.args = event.args
              }
            },
            onToolResult: (event: { toolUseId: string; name: string; result: unknown }) => {
              const tc = streamingToolCalls.value.find((t) => t.id === event.toolUseId)
              if (tc) {
                if (tc.completedAt && tc.status === 'completed') {
                  return
                }
                tc.status = 'completed'
                tc.result = event.result
                tc.completedAt = Date.now()
              }
            },
            onThinking: (thinkContent: string, blockIndex: number) => {
              const existing = streamingThinkingBlocks.value.find(s => s.index === blockIndex)
              if (existing) {
                existing.content += thinkContent
              } else {
                streamingThinkingBlocks.value.push({
                  index: blockIndex,
                  content: thinkContent,
                  textPosition: streamingToken.value.length,
                  renderOrder: streamingRenderOrder++,
                })
              }
            },
            onUsage: (usage) => {
              streamingUsage.value = usage
            },
            onRetry: (event) => {
              retryStatus.value = {
                attempt: event.attempt,
                maxRetries: event.maxRetries,
                delayMs: event.delayMs,
                status: event.status,
              }
            },
            onDone: async () => {
              try {
                const updates: Partial<ChatMessage> = {
                  content: streamingToken.value,
                  thinkingBlocks: streamingThinkingBlocks.value.length > 0
                    ? JSON.parse(JSON.stringify(streamingThinkingBlocks.value))
                    : undefined,
                  toolCalls: streamingToolCalls.value.length > 0
                    ? JSON.parse(JSON.stringify(toRaw(streamingToolCalls.value)))
                    : undefined,
                  usage: streamingUsage.value
                    ? { ...toRaw(streamingUsage.value) }
                    : undefined,
                }
                await dbUpdateMessage(assistantMsg.id, updates)
                const msgIndex = messages.value.findIndex((m) => m.id === assistantMsg.id)
                if (msgIndex !== -1) {
                  messages.value[msgIndex] = { ...messages.value[msgIndex], ...updates }
                }
              } finally {
                retryStatus.value = null
                isStreaming.value = false
                abortController.value = null
                streamingMessageId.value = null
                streamCleanup = null
                currentRequestId = null
              }
            },
            onError: async (error: Error) => {
              try {
                const updates: Partial<ChatMessage> = {
                  content: streamingToken.value || `[错误] ${error.message}`,
                }
                await dbUpdateMessage(assistantMsg.id, updates)
                const msgIndex = messages.value.findIndex((m) => m.id === assistantMsg.id)
                if (msgIndex !== -1) {
                  messages.value[msgIndex] = { ...messages.value[msgIndex], ...updates }
                }
              } finally {
                retryStatus.value = null
                isStreaming.value = false
                abortController.value = null
                streamingMessageId.value = null
                streamCleanup = null
                currentRequestId = null
              }
            },
          },
          uiStore.targetTabId,
          uiStore.enabledToolNames,
          workflowOptions,
        )

        if (result) {
          currentRequestId = result.requestId
          streamCleanup = result.cleanup
        }
      } catch (error) {
        isStreaming.value = false
        abortController.value = null
        streamingMessageId.value = null
        streamCleanup = null
        currentRequestId = null
        const msgIndex = messages.value.findIndex((m) => m.id === assistantMsg.id)
        if (msgIndex !== -1) {
          const errorContent = error instanceof Error ? error.message : String(error)
          messages.value[msgIndex] = { ...messages.value[msgIndex], content: `[错误] ${errorContent}` }
          await dbUpdateMessage(assistantMsg.id, { content: `[错误] ${errorContent}` })
        }
      }
    }

    async function sendMessage(content: string, images?: string[]) {
      if (isStreaming.value) return

      if (!currentSessionId.value) {
        await createSession()
      }
      const sessionId = currentSessionId.value!

      const userMsg = await dbAddMessage({
        sessionId,
        role: 'user',
        content,
        images,
        createdAt: Date.now(),
      })
      messages.value.push(userMsg)

      // 首条消息时自动设置标题
      const session = sessions.value.find((s) => s.id === sessionId)
      if (session && session.messageCount <= 1) {
        const title = content.slice(0, 50) + (content.length > 50 ? '...' : '')
        await dbUpdateSessionTitle(sessionId, title)
        session.title = title
      }

      await streamAssistantReply(content, images)
    }

    async function stopGeneration() {
      if (!abortController.value) return

      if (currentRequestId) {
        window.api.chat.abort(currentRequestId).catch(() => {})
        currentRequestId = null
      }
      abortController.value = null

      streamCleanup?.()
      streamCleanup = null

      const msgId = streamingMessageId.value
      if (msgId) {
        const updates: Partial<ChatMessage> = {
          content: streamingToken.value,
          thinkingBlocks: streamingThinkingBlocks.value.length > 0
            ? JSON.parse(JSON.stringify(streamingThinkingBlocks.value))
            : undefined,
          toolCalls: streamingToolCalls.value.length > 0
            ? JSON.parse(JSON.stringify(toRaw(streamingToolCalls.value)))
            : undefined,
        }
        await dbUpdateMessage(msgId, updates)
        const msgIndex = messages.value.findIndex((m) => m.id === msgId)
        if (msgIndex !== -1) {
          messages.value[msgIndex] = { ...messages.value[msgIndex], ...updates }
        }
      }

      // 追加系统消息
      const sessionId = currentSessionId.value
      if (sessionId) {
        const systemMsg = await dbAddMessage({
          sessionId,
          role: 'system',
          content: '用户已中断操作',
          createdAt: Date.now(),
        })
        messages.value.push(systemMsg)
      }

      isStreaming.value = false
      streamingMessageId.value = null
      retryStatus.value = null
    }

    // ===== 消息操作 =====

    async function deleteMessageById(messageId: string) {
      await dbDeleteMessage(messageId)
      messages.value = messages.value.filter((m) => m.id !== messageId)
    }

    async function deleteMessageAndAfter(messageId: string) {
      const index = messages.value.findIndex((m) => m.id === messageId)
      if (index === -1) return
      const idsToDelete = messages.value.slice(index).map((m) => m.id)
      await dbDeleteMessages(idsToDelete)
      messages.value = messages.value.slice(0, index)
    }

    async function retryMessage(messageId: string) {
      if (isStreaming.value) return
      const index = messages.value.findIndex((m) => m.id === messageId)
      if (index === -1) return

      let userMsgIndex = -1
      for (let i = index - 1; i >= 0; i--) {
        if (messages.value[i].role === 'user') {
          userMsgIndex = i
          break
        }
      }
      if (userMsgIndex === -1) return

      const userMsg = messages.value[userMsgIndex]
      const userContent = userMsg.content
      const userImages = userMsg.images

      const idsToDelete = messages.value.slice(index).map((m) => m.id)
      await dbDeleteMessages(idsToDelete)
      messages.value = messages.value.slice(0, index)

      await streamAssistantReply(userContent, userImages)
    }

    async function editMessage(messageId: string, newContent: string) {
      if (isStreaming.value) return
      const index = messages.value.findIndex((m) => m.id === messageId)
      if (index === -1) return

      await dbUpdateMessage(messageId, { content: newContent })
      messages.value[index] = { ...messages.value[index], content: newContent }

      if (index < messages.value.length - 1) {
        const idsToDelete = messages.value.slice(index + 1).map((m) => m.id)
        await dbDeleteMessages(idsToDelete)
        messages.value = messages.value.slice(0, index + 1)
      }

      await streamAssistantReply(newContent, messages.value[index].images)
    }

    async function rerunTool(messageId: string, toolCallId: string) {
      if (isStreaming.value) return
      const msgIndex = messages.value.findIndex((m) => m.id === messageId)
      if (msgIndex === -1) return
      const msg = messages.value[msgIndex]
      if (!msg.toolCalls) return
      const tcIndex = msg.toolCalls.findIndex((tc) => tc.id === toolCallId)
      if (tcIndex === -1) return

      const tc = msg.toolCalls[tcIndex]
      const uiStore = useChatUIStore()
      const targetTabId = uiStore.targetTabId || currentSession.value?.browserViewId || undefined
      const rerunArgs = JSON.parse(JSON.stringify(toRaw(tc.args ?? {})))

      const updatedCalls = [...msg.toolCalls]
      updatedCalls[tcIndex] = { ...tc, status: 'running' as const, result: undefined, error: undefined, startedAt: Date.now(), completedAt: undefined }
      const updates: Partial<ChatMessage> = { toolCalls: updatedCalls }
      messages.value[msgIndex] = { ...msg, ...updates }

      try {
        const rawResult = await window.api.agent.execTool(tc.name, rerunArgs, targetTabId)
        const result = JSON.parse(JSON.stringify(rawResult))
        const now = Date.now()
        const hasError = result && typeof result === 'object' && 'error' in result
        const finalCalls = [...updatedCalls]
        finalCalls[tcIndex] = {
          ...updatedCalls[tcIndex],
          status: hasError ? 'error' : ('completed' as const),
          result: hasError ? undefined : result,
          error: hasError ? (result as { error: string }).error : undefined,
          completedAt: now,
        }
        const finalUpdates: Partial<ChatMessage> = {
          toolCalls: JSON.parse(JSON.stringify(toRaw(finalCalls))),
        }
        await dbUpdateMessage(messageId, finalUpdates)
        messages.value[msgIndex] = { ...messages.value[msgIndex], ...finalUpdates }
      } catch (err) {
        const now = Date.now()
        const finalCalls = [...updatedCalls]
        finalCalls[tcIndex] = {
          ...updatedCalls[tcIndex],
          status: 'error' as const,
          error: err instanceof Error ? err.message : String(err),
          completedAt: now,
        }
        const finalUpdates: Partial<ChatMessage> = {
          toolCalls: JSON.parse(JSON.stringify(toRaw(finalCalls))),
        }
        await dbUpdateMessage(messageId, finalUpdates)
        messages.value[msgIndex] = { ...messages.value[msgIndex], ...finalUpdates }
      }
    }

    // ===== 工作流会话管理 =====

    async function switchToWorkflowSession(workflowId: string | undefined) {
      if (!workflowId) return

      const existing = sessions.value.find((s) => s.workflowId === workflowId)
      if (existing) {
        if (currentSessionId.value === existing.id) return
        currentSessionId.value = existing.id
        messages.value = await dbListMessages(existing.id)
        return
      }

      const providerStore = useAIProviderStore()
      if (!providerStore.currentProvider || !providerStore.currentModel) {
        throw new Error('请先选择 AI 模型')
      }
      const session = await dbCreateSession(
        scope,
        providerStore.currentModel.id,
        providerStore.currentProvider.id,
        null,
        workflowId,
      )
      sessions.value.unshift(session)
      currentSessionId.value = session.id
      messages.value = []
    }

    // ===== 初始化 =====

    async function init() {
      await loadSessions()

      if (sessions.value.length > 0 && !currentSessionId.value) {
        await switchSession(sessions.value[0].id)
      }
    }

    return {
      scope,
      sessions,
      currentSessionId,
      messages,
      isStreaming,
      streamingToken,
      streamingToolCalls,
      streamingThinkingBlocks,
      streamingUsage,
      retryStatus,
      currentSession,
      loadSessions,
      createSession,
      deleteSessionById,
      switchSession,
      clearSessionMessages,
      sendMessage,
      streamAssistantReply,
      stopGeneration,
      deleteMessageById,
      deleteMessageAndAfter,
      retryMessage,
      editMessage,
      rerunTool,
      switchToWorkflowSession,
      init,
    }
  })()
}

export type ChatStoreInstance = ReturnType<typeof createChatStore>

import { defineStore } from 'pinia'
import { computed, ref, watch } from 'vue'
import type {
  SplitDropPosition,
  SplitLayout,
  SplitLayoutType,
  SplitNode,
  SplitPane,
  SplitPresetType,
  SavedSplitScheme
} from '../types'
import {
  buildFallbackTree,
  buildPresetTree,
  cloneSplitNode,
  collectPaneIds,
  countSplitLeaves,
  detectLayoutType,
  movePaneInTree,
  normalizeSizes,
  removePaneFromTree,
  remapTreePaneIds,
  reorderPanesByTree,
  updateBranchSizesAtPath
} from '@/lib/split-layout'
import { useTabStore } from './tab'
import { useWorkspaceStore } from './workspace'

const api = window.api

/** Generate unique pane ID */
function generatePaneId(): string {
  return `pane-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`
}

const PRESET_PANE_COUNTS: Record<Exclude<SplitPresetType, '1'>, number> = {
  '2h': 2,
  '2v': 2,
  '3': 3,
  '4': 4
}

function getLayoutDirection(root: SplitNode): 'horizontal' | 'vertical' {
  return root.kind === 'branch' ? root.direction : 'horizontal'
}

function getLayoutSizes(root: SplitNode): number[] {
  return root.kind === 'branch' ? [...root.sizes] : [100]
}

function isPresetType(value: string): value is Exclude<SplitPresetType, '1'> {
  return value in PRESET_PANE_COUNTS
}

function isCompatibleRoot(root: SplitNode, panes: SplitPane[]): boolean {
  const paneIds = new Set(panes.map((pane) => pane.id))
  const layoutPaneIds = collectPaneIds(root)
  return layoutPaneIds.length === panes.length && layoutPaneIds.every((paneId) => paneIds.has(paneId))
}

function buildRuntimeRoot(
  presetType: string,
  panes: SplitPane[],
  root?: SplitNode
): SplitNode {
  if (root && isCompatibleRoot(root, panes)) {
    return cloneSplitNode(root)
  }

  if (isPresetType(presetType)) {
    return buildPresetTree(presetType, panes)
  }

  return buildFallbackTree(panes)
}

function buildSchemeRoot(
  presetType: string,
  panes: SplitPane[],
  root?: SplitNode
): SplitNode {
  if (root) {
    return remapTreePaneIds(cloneSplitNode(root), panes.map((pane) => pane.id))
  }

  if (isPresetType(presetType)) {
    return buildPresetTree(presetType, panes)
  }

  return buildFallbackTree(panes)
}

function resolvePaneCountForScheme(scheme: SavedSplitScheme): number {
  if (scheme.root) {
    return countSplitLeaves(scheme.root)
  }

  if (scheme.paneCount > 1) {
    return scheme.paneCount
  }

  if (isPresetType(scheme.presetType)) {
    return PRESET_PANE_COUNTS[scheme.presetType]
  }

  return 2
}

export const useSplitStore = defineStore('split', () => {
  const tabStore = useTabStore()
  const workspaceStore = useWorkspaceStore()

  // ====== State ======
  const activeLayout = ref<SplitLayout | null>(null)
  const focusedPaneId = ref<string | null>(null)
  const savedSchemes = ref<SavedSplitScheme[]>([])
  const layoutRevision = ref(0)
  const manualAdjustEnabled = ref(false)

  // ====== Computed ======
  const paneCount = computed(() => activeLayout.value?.panes.length ?? 1)
  const isSplitActive = computed(() => paneCount.value > 1)
  const activePanes = computed(() => activeLayout.value?.panes ?? [])

  /** Get the pane that currently has focus */
  const focusedPane = computed(() =>
    activeLayout.value?.panes.find((pane) => pane.id === focusedPaneId.value) ?? null
  )

  // ====== Actions ======

  function bumpLayoutRevision() {
    layoutRevision.value += 1
  }

  function createPanes(nextPaneCount: number): SplitPane[] {
    const workspaceTabs = tabStore.workspaceTabs
    const panes: SplitPane[] = []

    for (let index = 0; index < nextPaneCount; index += 1) {
      panes.push({
        id: generatePaneId(),
        activeTabId: workspaceTabs[index]?.id ?? null,
        order: index
      })
    }

    return panes
  }

  function getInitialPaneId(panes: SplitPane[], preferredPaneId?: string | null): string | null {
    if (preferredPaneId && panes.some((pane) => pane.id === preferredPaneId)) {
      return preferredPaneId
    }

    return panes.find((pane) => pane.activeTabId)?.id ?? panes[0]?.id ?? null
  }

  function resolveNewTabPaneId(preferredPaneId?: string | null): string | null {
    const panes = activeLayout.value?.panes ?? []
    if (panes.length === 0) return null

    if (preferredPaneId && panes.some((pane) => pane.id === preferredPaneId)) {
      return preferredPaneId
    }

    const focusedPane = panes.find((pane) => pane.id === focusedPaneId.value)
    if (focusedPane && !focusedPane.activeTabId) {
      return focusedPane.id
    }

    return panes.find((pane) => !pane.activeTabId)?.id ?? focusedPane?.id ?? panes[0]?.id ?? null
  }

  function getReplacementTabId(closedTabId: string, pane: SplitPane): string | null {
    if (!activeLayout.value) return null

    const occupiedTabIds = new Set(
      activeLayout.value.panes
        .filter((item) => item.id !== pane.id)
        .map((item) => item.activeTabId)
        .filter((tabId): tabId is string => !!tabId)
    )

    const availableTabs = tabStore.workspaceTabs.filter((tab) =>
      tab.id !== closedTabId
      && !occupiedTabIds.has(tab.id)
      && !tab.url?.startsWith('sessionbox://')
    )

    if (availableTabs.length === 0) return null

    return availableTabs[Math.min(pane.order, availableTabs.length - 1)]?.id ?? availableTabs[0]?.id ?? null
  }

  function applyLayout(
    presetType: SplitLayoutType,
    panes: SplitPane[],
    root: SplitNode,
    preferredPaneId?: string | null
  ) {
    const normalizedRoot = cloneSplitNode(root)
    const orderedPanes = reorderPanesByTree(panes, normalizedRoot)
    const detectedPresetType = detectLayoutType(normalizedRoot)
    const resolvedPresetType = presetType === 'custom' ? detectedPresetType : presetType

    activeLayout.value = {
      presetType: resolvedPresetType,
      panes: orderedPanes,
      direction: getLayoutDirection(normalizedRoot),
      sizes: getLayoutSizes(normalizedRoot),
      root: normalizedRoot
    }

    focusedPaneId.value = getInitialPaneId(orderedPanes, preferredPaneId)
    if (orderedPanes.length <= 1) {
      manualAdjustEnabled.value = false
    }

    bumpLayoutRevision()

    if (focusedPaneId.value) {
      focusPane(focusedPaneId.value)
    }

    void persistState()
  }

  /** Apply a preset split layout */
  function applyPreset(type: SplitPresetType) {
    if (type === '1') {
      resetToSingle()
      return
    }

    const panes = createPanes(PRESET_PANE_COUNTS[type])
    applyLayout(type, panes, buildPresetTree(type, panes))
  }

  /** Apply a saved scheme */
  function applyScheme(schemeId: string) {
    const scheme = savedSchemes.value.find((item) => item.id === schemeId)
    if (!scheme) return

    const panes = createPanes(resolvePaneCountForScheme(scheme))
    const root = buildSchemeRoot(scheme.presetType, panes, scheme.root)
    applyLayout(scheme.presetType, panes, root)
  }

  function setManualAdjustEnabled(enabled: boolean) {
    manualAdjustEnabled.value = enabled && isSplitActive.value
    if (activeLayout.value) {
      void persistState()
    }
  }

  /** Reset to single pane mode */
  function resetToSingle() {
    const currentTabId = focusedPane.value?.activeTabId ?? tabStore.activeTabId

    activeLayout.value = null
    focusedPaneId.value = null
    manualAdjustEnabled.value = false
    bumpLayoutRevision()

    if (currentTabId) {
      void tabStore.switchTab(currentTabId)
    }

    void persistState()
  }

  /** Set the active tab for a specific pane */
  function setPaneActiveTab(paneId: string, tabId: string | null) {
    if (!activeLayout.value) return
    const pane = activeLayout.value.panes.find((item) => item.id === paneId)
    if (pane) {
      pane.activeTabId = tabId
    }
  }

  /** Focus a specific pane */
  function focusPane(paneId: string) {
    const pane = activeLayout.value?.panes.find((item) => item.id === paneId)
    if (!pane) return

    focusedPaneId.value = paneId

    if (!pane.activeTabId) return

    tabStore.activeTabId = pane.activeTabId
    void api.tab.switch(pane.activeTabId)
  }

  /** Handle a tab click — route to the focused pane */
  function handleTabClick(tabId: string): boolean {
    if (!isSplitActive.value || !activeLayout.value) return false

    const targetPaneId = focusedPaneId.value ?? activeLayout.value.panes[0]?.id
    if (!targetPaneId) return false

    for (const pane of activeLayout.value.panes) {
      if (pane.activeTabId === tabId) {
        focusPane(pane.id)
        return true
      }
    }

    setPaneActiveTab(targetPaneId, tabId)
    focusPane(targetPaneId)
    return true
  }

  /** Handle tab close — clean up pane references */
  function handleTabClosed(tabId: string) {
    if (!activeLayout.value) return

    for (const pane of activeLayout.value.panes) {
      if (pane.activeTabId === tabId) {
        pane.activeTabId = getReplacementTabId(tabId, pane)
      }
    }
  }

  /** Handle new tab creation — prefer requested or empty pane before falling back */
  function handleTabCreated(tabId: string, preferredPaneId?: string | null) {
    if (!isSplitActive.value || !activeLayout.value) return
    const targetPaneId = resolveNewTabPaneId(preferredPaneId)
    if (targetPaneId) {
      setPaneActiveTab(targetPaneId, tabId)
      focusPane(targetPaneId)
    }
  }

  function removePane(paneId: string) {
    if (!activeLayout.value || activeLayout.value.panes.length <= 1) return

    const removedPane = activeLayout.value.panes.find((pane) => pane.id === paneId)
    if (!removedPane) return

    const nextPanes = activeLayout.value.panes.filter((pane) => pane.id !== paneId)
    if (nextPanes.length === 0) return

    if (nextPanes.length === 1) {
      const nextTabId = nextPanes[0]?.activeTabId ?? removedPane.activeTabId ?? tabStore.activeTabId

      activeLayout.value = null
      focusedPaneId.value = null
      manualAdjustEnabled.value = false
      bumpLayoutRevision()

      if (nextTabId) {
        void tabStore.switchTab(nextTabId)
      }

      void persistState()
      return
    }

    const nextRoot = removePaneFromTree(activeLayout.value.root, paneId)
    if (!nextRoot) return

    const preferredPaneId = focusedPaneId.value && focusedPaneId.value !== paneId
      ? focusedPaneId.value
      : nextPanes.find((pane) => pane.activeTabId)?.id ?? nextPanes[0]?.id ?? null

    applyLayout('custom', nextPanes, nextRoot, preferredPaneId)
  }

  function movePane(
    sourcePaneId: string,
    targetPaneId: string,
    position: SplitDropPosition,
    metrics?: { sourceSize?: number; targetSize?: number }
  ) {
    if (!activeLayout.value || sourcePaneId === targetPaneId && position !== 'center') return

    const nextRoot = movePaneInTree(
      activeLayout.value.root,
      sourcePaneId,
      targetPaneId,
      position,
      normalizeSizes([metrics?.sourceSize ?? 1, metrics?.targetSize ?? 1], 2)
    )

    applyLayout('custom', activeLayout.value.panes, nextRoot, focusedPaneId.value)
  }

  function updateBranchSizes(path: number[], sizes: number[]) {
    if (!activeLayout.value) return

    const nextRoot = updateBranchSizesAtPath(activeLayout.value.root, path, sizes)
    activeLayout.value = {
      ...activeLayout.value,
      root: nextRoot,
      direction: getLayoutDirection(nextRoot),
      sizes: getLayoutSizes(nextRoot),
      panes: reorderPanesByTree(activeLayout.value.panes, nextRoot)
    }
  }

  /** Save current layout as a custom scheme */
  async function saveScheme(name: string) {
    if (!activeLayout.value) return

    const scheme: SavedSplitScheme = {
      id: `scheme-${Date.now()}`,
      name,
      presetType: activeLayout.value.presetType,
      direction: activeLayout.value.direction,
      paneCount: countSplitLeaves(activeLayout.value.root),
      sizes: [...activeLayout.value.sizes],
      root: cloneSplitNode(activeLayout.value.root)
    }

    await api.split.createScheme(scheme)
    savedSchemes.value.push(scheme)
  }

  /** Delete a saved scheme */
  async function deleteScheme(id: string) {
    await api.split.deleteScheme(id)
    savedSchemes.value = savedSchemes.value.filter((scheme) => scheme.id !== id)
  }

  /** Load saved schemes from main process */
  async function loadSchemes() {
    savedSchemes.value = await api.split.listSchemes()
  }

  /** Persist current split state to main process */
  async function persistState(targetWorkspaceId = workspaceStore.activeWorkspaceId) {
    const workspaceId = targetWorkspaceId

    if (activeLayout.value) {
      await api.split.setState(workspaceId, {
        presetType: activeLayout.value.presetType,
        panes: activeLayout.value.panes.map((pane) => ({
          id: pane.id,
          activeTabId: pane.activeTabId,
          order: pane.order
        })),
        direction: activeLayout.value.direction,
        sizes: [...activeLayout.value.sizes],
        manualAdjustEnabled: manualAdjustEnabled.value,
        root: cloneSplitNode(activeLayout.value.root)
      })
    } else {
      await api.split.clearState(workspaceId)
    }
  }

  /** Restore split state for the current workspace */
  async function restoreState(targetWorkspaceId = workspaceStore.activeWorkspaceId) {
    const data = await api.split.getState(targetWorkspaceId)

    manualAdjustEnabled.value = false

    if (data) {
      const panes = data.panes.map((pane) => ({
        id: pane.id,
        activeTabId: pane.activeTabId,
        order: pane.order
      }))

      const root = buildRuntimeRoot(data.presetType, panes, data.root as SplitNode | undefined)
      const orderedPanes = reorderPanesByTree(panes, root)

      activeLayout.value = {
        presetType: detectLayoutType(root),
        panes: orderedPanes,
        direction: getLayoutDirection(root),
        sizes: getLayoutSizes(root),
        root
      }

      focusedPaneId.value = getInitialPaneId(orderedPanes)
      manualAdjustEnabled.value = !!data.manualAdjustEnabled && orderedPanes.length > 1
      bumpLayoutRevision()

      if (focusedPaneId.value) {
        focusPane(focusedPaneId.value)
      }
      return
    }

    activeLayout.value = null
    focusedPaneId.value = null
    bumpLayoutRevision()
  }

  watch(
    () => tabStore.activeTabId,
    (tabId) => {
      if (!isSplitActive.value || !tabId) return

      const pane = activeLayout.value?.panes.find((item) => item.activeTabId === tabId)
      if (pane && focusedPaneId.value !== pane.id) {
        focusedPaneId.value = pane.id
      }
    }
  )

  watch(
    isSplitActive,
    (active) => {
      if (!active) {
        manualAdjustEnabled.value = false
      }
    }
  )

  // ====== Workspace switch watcher ======
  watch(
    () => workspaceStore.activeWorkspaceId,
    async (nextWorkspaceId, previousWorkspaceId) => {
      if (activeLayout.value && previousWorkspaceId) {
        await persistState(previousWorkspaceId)
      }
      await restoreState(nextWorkspaceId)
    }
  )

  return {
    activeLayout,
    focusedPaneId,
    savedSchemes,
    layoutRevision,
    manualAdjustEnabled,
    paneCount,
    isSplitActive,
    activePanes,
    focusedPane,
    applyPreset,
    resetToSingle,
    setPaneActiveTab,
    focusPane,
    handleTabClick,
    handleTabClosed,
    handleTabCreated,
    removePane,
    movePane,
    updateBranchSizes,
    setManualAdjustEnabled,
    applyScheme,
    saveScheme,
    deleteScheme,
    loadSchemes,
    restoreState,
    persistState
  }
})

import { defineStore } from 'pinia'
import { ref, computed, watch, nextTick } from 'vue'
import type { Tab, NavState } from '../types'
import { useContainerStore } from './container'
import { usePageStore } from './page'
import { useSnifferStore } from './sniffer'
import { useWorkspaceStore } from './workspace'
import { useHistoryStore } from './history'

const api = window.api

export type TabLayout = 'horizontal' | 'vertical'
export type TabGroupMode = 'none' | 'group' | 'account'

const TAB_LAYOUT_KEY = 'sessionbox-tab-layout'
const BOOKMARK_BAR_KEY = 'sessionbox-bookmark-bar-visible'
const TAB_GROUP_KEY = 'sessionbox-tab-group-mode'
const ACTIVE_TAB_KEY = 'sessionbox-active-tab-id'

export const useTabStore = defineStore('tab', () => {
  interface TabProxyInfo {
    enabled: boolean
    applied?: boolean
    name?: string
    ip?: string
    text?: string
    error?: string
    status?: 'idle' | 'checking' | 'success' | 'error'
    proxyMode?: 'global' | 'custom' | 'pac_url'
    proxyId?: string
    isOverride?: boolean
  }
  // ====== 状态 ======
  const tabs = ref<Tab[]>([])
  const activeTabId = ref<string | null>(null)
  const tabGroupFilterId = ref<string | null>(null)
  const navStates = ref<Map<string, NavState>>(new Map())
  const favicons = ref<Map<string, string>>(new Map())
  /** favicon 缓存版本号（domain → 版本），用于强制刷新 <img> */
  const faviconVersions = ref<Map<string, number>>(new Map())
  const frozenTabIds = ref<Set<string>>(new Set())
  const proxyInfos = ref<Map<string, TabProxyInfo>>(new Map())
  const mutedSites = ref<string[]>([])
  const zoomLevels = ref<Map<string, number>>(new Map())
  /** 待选择容器后打开的外部 URL（非 null 时弹出容器选择对话框） */
  const pendingExternalUrl = ref<string | null>(null)
  let listenersReady = false
  let restoreReady = false

  // ====== 关闭标签页历史栈（用于 Ctrl+Shift+T 恢复） ======
  const MAX_RECENTLY_CLOSED = 20
  interface ClosedTabSnapshot {
    pageId: string
    title: string
    url: string
    order: number
  }
  const recentlyClosedTabs = ref<ClosedTabSnapshot[]>([])

  // ====== 标签栏布局 ======
  const tabLayout = ref<TabLayout>(
    (localStorage.getItem(TAB_LAYOUT_KEY) as TabLayout) || 'horizontal'
  )

  function toggleLayout() {
    tabLayout.value = tabLayout.value === 'horizontal' ? 'vertical' : 'horizontal'
    localStorage.setItem(TAB_LAYOUT_KEY, tabLayout.value)
  }

  // ====== 快捷网站栏显隐 ======
  const bookmarkBarVisible = ref(localStorage.getItem(BOOKMARK_BAR_KEY) !== 'false')

  function toggleBookmarkBar() {
    bookmarkBarVisible.value = !bookmarkBarVisible.value
    localStorage.setItem(BOOKMARK_BAR_KEY, String(bookmarkBarVisible.value))
  }

  // ====== 标签页分组模式 ======
  function loadTabGroupMode(): TabGroupMode {
    const stored = localStorage.getItem(TAB_GROUP_KEY)
    // 兼容旧版 boolean 值
    if (stored === 'true') return 'group'
    if (stored === 'group' || stored === 'account') return stored
    return 'none'
  }
  const tabGroupMode = ref<TabGroupMode>(loadTabGroupMode())

  function setTabGroupMode(mode: TabGroupMode) {
    tabGroupMode.value = mode
    localStorage.setItem(TAB_GROUP_KEY, mode)
  }

  /** 设置标签分组过滤（仅展示指定分组的标签，null 表示不过滤） */
  function setTabGroupFilter(groupId: string | null) {
    tabGroupFilterId.value = groupId
  }

  /** 清除标签分组过滤 */
  function clearTabGroupFilter() {
    tabGroupFilterId.value = null
  }

  /** 是否启用了任意分组 */
  const tabGroupEnabled = computed(() => tabGroupMode.value !== 'none')

  /** 按 tab 的 order 排列，同组标签聚拢在一起；拖拽 tab 改变 order 即改变位置和分组顺序 */
  const groupedSortedTabs = computed(() => {
    if (!tabGroupEnabled.value) return sortedTabs.value

    const pageStore = usePageStore()
    const containerStore = useContainerStore()
    const groupByContainer = tabGroupMode.value === 'account'

    // 按 tab 原有 order 分组
    const groupMap = new Map<string, { name: string; color?: string; tabs: Tab[] }>()
    for (const tab of sortedTabs.value) {
      const page = pageStore.getPage(tab.pageId)
      if (!page) continue

      let key: string, name: string, color: string | undefined
      if (groupByContainer) {
        key = page.containerId || '__default__'
        const container = page.containerId ? containerStore.getContainer(page.containerId) : undefined
        name = container?.name ?? '默认容器'
        color = undefined
      } else {
        const group = containerStore.getGroup(page.groupId)
        key = group?.id ?? '__ungrouped__'
        name = group?.name ?? '未分组'
        color = group?.color
      }
      if (!groupMap.has(key)) groupMap.set(key, { name, color, tabs: [] })
      groupMap.get(key)!.tabs.push(tab)
    }

    // 按 tabs 数组中第一个 tab 的 order 决定分组间排序
    const sortedGroups = [...groupMap.entries()].sort((a, b) => {
      const orderA = a[1].tabs[0]?.order ?? 0
      const orderB = b[1].tabs[0]?.order ?? 0
      return orderA - orderB
    })

    // 扁平化为带分组标记的列表
    const result: (Tab & { groupName: string; groupColor?: string; isGroupStart: boolean })[] = []
    for (const [, group] of sortedGroups) {
      group.tabs.forEach((tab, i) => {
        result.push({ ...tab, groupName: group.name, groupColor: group.color, isGroupStart: i === 0 })
      })
    }
    return result
  })

  // ====== 计算属性 ======

  /** 排序后的标签列表（固定标签排在最前） */
  const sortedTabs = computed(() =>
    [...tabs.value].sort((a, b) => {
      // 固定标签优先
      if (a.pinned && !b.pinned) return -1
      if (!a.pinned && b.pinned) return 1
      return a.order - b.order
    })
  )

  /** 根据当前工作区过滤的标签列表 */
  const workspaceTabs = computed(() => {
    const pageStore = usePageStore()
    const containerStore = useContainerStore()
    const workspaceStore = useWorkspaceStore()
    const activeId = workspaceStore.activeWorkspaceId
    // 获取当前工作区的所有 page ID（通过 page 的 groupId 找到 group，再匹配 workspaceId）
    const pageIds = new Set(
      pageStore.pages
        .filter((p) => {
          const group = containerStore.getGroup(p.groupId)
          const gWorkspaceId = group?.workspaceId || '__default__'
          return gWorkspaceId === activeId
        })
        .map((p) => p.id)
    )
    // 包含：page 匹配当前工作区的 tab、无 page 但 workspaceId 匹配的 tab、
    // 无 page 且无 workspaceId 的内部页面 tab（全局可见）
    let result = sortedTabs.value.filter((t) => {
      if (t.pageId) return pageIds.has(t.pageId)
      // 无 pageId 的 tab：按 workspaceId 归属过滤
      if (t.workspaceId) return t.workspaceId === activeId
      // 无 pageId 也无 workspaceId：内部页面，全局可见
      return true
    })

    // 如果设置了分组过滤，只保留对应分组的标签
    if (tabGroupFilterId.value) {
      const filteredPageIds = new Set(
        pageStore.pages
          .filter((p) => p.groupId === tabGroupFilterId.value)
          .map((p) => p.id)
      )
      result = result.filter((t) => filteredPageIds.has(t.pageId) || !t.pageId)
    }

    return result
  })

  /** 工作区内带分组标记的标签列表 */
  const groupedWorkspaceTabs = computed(() => {
    if (!tabGroupEnabled.value) return workspaceTabs.value

    const pageStore = usePageStore()
    const containerStore = useContainerStore()
    const groupByContainer = tabGroupMode.value === 'account'
    const groupMap = new Map<string, { name: string; color?: string; tabs: Tab[] }>()
    const internalTabs: (Tab & { groupName: string; groupColor?: string; isGroupStart: boolean })[] = []

    for (const tab of workspaceTabs.value) {
      const page = pageStore.getPage(tab.pageId)
      // 内部页面 tab（无 page）单独收集，不显示分组标识
      if (!page) {
        internalTabs.push({ ...tab, groupName: '', groupColor: undefined, isGroupStart: false })
        continue
      }

      let key: string, name: string, color: string | undefined
      if (groupByContainer) {
        key = page.containerId || '__default__'
        const container = page.containerId ? containerStore.getContainer(page.containerId) : undefined
        name = container?.name ?? '默认容器'
        color = undefined
      } else {
        const group = containerStore.getGroup(page.groupId)
        key = group?.id ?? '__ungrouped__'
        name = group?.name ?? '未分组'
        color = group?.color
      }
      if (!groupMap.has(key)) groupMap.set(key, { name, color, tabs: [] })
      groupMap.get(key)!.tabs.push(tab)
    }

    const sortedGroups = [...groupMap.entries()].sort((a, b) => {
      const orderA = a[1].tabs[0]?.order ?? 0
      const orderB = b[1].tabs[0]?.order ?? 0
      return orderA - orderB
    })

    const result: (Tab & { groupName: string; groupColor?: string; isGroupStart: boolean })[] = []
    for (const [, group] of sortedGroups) {
      group.tabs.forEach((tab, i) => {
        result.push({ ...tab, groupName: group.name, groupColor: group.color, isGroupStart: i === 0 })
      })
    }
    // 内部页面 tab 放在最后
    result.push(...internalTabs)
    return result
  })

  /** 当前激活的标签 */
  const activeTab = computed(() =>
    tabs.value.find((t) => t.id === activeTabId.value) ?? null
  )

  /** 当前激活标签的导航状态 */
  const activeNavState = computed((): NavState => {
    if (!activeTabId.value) return { canGoBack: false, canGoForward: false, isLoading: false }
    return navStates.value.get(activeTabId.value) ?? { canGoBack: false, canGoForward: false, isLoading: false }
  })

  const activeProxyInfo = computed((): TabProxyInfo | null => {
    if (!activeTabId.value) return null
    return proxyInfos.value.get(activeTabId.value) ?? null
  })

  /** 当前激活标签的缩放级别 */
  const activeZoomLevel = computed((): number => {
    if (!activeTabId.value) return 0
    return zoomLevels.value.get(activeTabId.value) ?? 0
  })

  /** 当前激活标签是否为内部页面 */
  const isInternalPage = computed(() => {
    const url = activeTab.value?.url
    return !!url?.startsWith('sessionbox://')
  })

  /** 内部页面的路径（如 'bookmarks'） */
  const internalPagePath = computed(() => {
    const url = activeTab.value?.url
    if (!url?.startsWith('sessionbox://')) return null
    return url.replace('sessionbox://', '')
  })

  // ====== 操作 ======

  async function loadTabs() {
    tabs.value = await api.tab.list()
  }

  async function activateCreatedTab(tabId: string, targetPaneId?: string | null) {
    const { useSplitStore } = await import('./split')
    const splitStore = useSplitStore()

    if (splitStore.isSplitActive) {
      splitStore.handleTabCreated(tabId, targetPaneId)
      return
    }

    await switchTab(tabId)
  }

  async function createTab(pageId: string, targetPaneId?: string | null) {
    const tab = await api.tab.create(pageId)
    // tab 由主进程 tab:created 事件添加
    await activateCreatedTab(tab.id, targetPaneId)
    return tab
  }

  /** 找到当前工作区的第一个 page，用于为无 pageId 的 tab 关联工作区 */
  function findPageInActiveWorkspace(): string | null {
    const pageStore = usePageStore()
    const containerStore = useContainerStore()
    const workspaceStore = useWorkspaceStore()
    const activeId = workspaceStore.activeWorkspaceId
    const page = pageStore.pages.find((p) => {
      const group = containerStore.getGroup(p.groupId)
      return (group?.workspaceId || '__default__') === activeId
    })
    return page?.id ?? null
  }

  /** 使用指定 URL 创建新 tab（用于快捷网站 / 新窗口拦截） */
  async function createTabForSite(url: string, pageId?: string, targetPaneId?: string | null) {
    const resolvedPageId = pageId || findPageInActiveWorkspace()
    const tab = await api.tab.create(resolvedPageId, url)
    // tab 由主进程 tab:created 事件添加，或 tab:activated 事件激活已有 tab
    await nextTick() // 确保 tab 先添加到列表再切换
    await activateCreatedTab(tab.id, targetPaneId)
    return tab
  }

  /** 使用指定 URL 创建新 tab（用于新窗口拦截） */
  async function createTabWithUrl(pageId: string, url: string, targetPaneId?: string | null) {
    const tab = await api.tab.create(pageId, url)
    // tab 由主进程 tab:created 事件添加
    await activateCreatedTab(tab.id, targetPaneId)
    return tab
  }

  async function closeTab(tabId: string) {
    // 保存关闭的 tab 快照（用于 Ctrl+Shift+T 恢复）
    const closingTab = tabs.value.find((t) => t.id === tabId)
    if (closingTab && closingTab.pageId && !closingTab.url?.startsWith('sessionbox://')) {
      recentlyClosedTabs.value.unshift({
        pageId: closingTab.pageId,
        title: closingTab.title,
        url: closingTab.url,
        order: closingTab.order
      })
      if (recentlyClosedTabs.value.length > MAX_RECENTLY_CLOSED) {
        recentlyClosedTabs.value.pop()
      }
    }

    const closingActive = activeTabId.value === tabId
    const currentWorkspaceTabs = workspaceTabs.value
    const currentIndex = currentWorkspaceTabs.findIndex((t) => t.id === tabId)
    const nextWorkspaceTabId = currentIndex === -1
      ? null
      : currentWorkspaceTabs[currentIndex + 1]?.id ?? currentWorkspaceTabs[currentIndex - 1]?.id ?? null

    await api.tab.close(tabId)
    tabs.value = tabs.value.filter((t) => t.id !== tabId)
    navStates.value.delete(tabId)

    // 清理嗅探器数据
    useSnifferStore().onTabClosed(tabId)
    favicons.value.delete(tabId)
    proxyInfos.value.delete(tabId)

    // Notify split store
    const { useSplitStore } = await import('./split')
    const splitStore = useSplitStore()
    splitStore.handleTabClosed(tabId)

    if (closingActive && splitStore.isSplitActive) {
      const nextSplitTabId = splitStore.focusedPane?.activeTabId
        ?? splitStore.activePanes.find((pane) => pane.activeTabId)?.activeTabId
        ?? null

      if (nextSplitTabId && workspaceTabs.value.some((t) => t.id === nextSplitTabId)) {
        await switchTab(nextSplitTabId)
      } else {
        activeTabId.value = null
        await api.tab.switch('')
      }
      return
    }

    // 如果关闭的是当前激活标签，只在当前工作区内选择相邻标签
    if (closingActive) {
      if (nextWorkspaceTabId && workspaceTabs.value.some((t) => t.id === nextWorkspaceTabId)) {
        await switchTab(nextWorkspaceTabId)
      } else {
        activeTabId.value = null
        await api.tab.switch('')
      }
    }
  }

  async function switchTab(tabId: string) {
    // Let split store handle tab routing if split is active
    const { useSplitStore } = await import('./split')
    const splitStore = useSplitStore()

    if (splitStore.isSplitActive) {
      splitStore.handleTabClick(tabId)
      return
    }

    activeTabId.value = tabId
    await api.tab.switch(tabId)
    fetchZoomLevel(tabId)
  }

  async function updateTab(tabId: string, data: Partial<Omit<Tab, 'id'>>) {
    await api.tab.update(tabId, data)
    const idx = tabs.value.findIndex((t) => t.id === tabId)
    if (idx !== -1) tabs.value[idx] = { ...tabs.value[idx], ...data }
  }

  async function reorderTabs(tabIds: string[]) {
    await api.tab.reorder(tabIds)
    tabIds.forEach((id, order) => {
      const t = tabs.value.find((t) => t.id === id)
      if (t) t.order = order
    })
  }

  async function navigate(tabId: string, url: string) {
    // 内部页面只更新元数据，不走 WebContentsView
    if (url.startsWith('sessionbox://')) {
      await updateTab(tabId, { url })
      return
    }
    await api.tab.navigate(tabId, url)
  }

  /** 打开内部页面（如书签管理、下载、历史记录） */
  async function openInternalPage(path: string) {
    const url = `sessionbox://${path}`
    if (activeTab.value) {
      await navigate(activeTab.value.id, url)
    } else {
      // 无活跃标签页时，创建新标签页打开
      await createTabForSite(url)
    }
  }

  async function goBack(tabId: string) {
    await api.tab.goBack(tabId)
  }

  async function goForward(tabId: string) {
    await api.tab.goForward(tabId)
  }

  async function reload(tabId: string) {
    await api.tab.reload(tabId)
  }

  /** 强制刷新（清除缓存） */
  async function forceReload(tabId: string) {
    await api.tab.forceReload(tabId)
  }

  /** 放大页面 */
  async function zoomIn(tabId: string) {
    await api.tab.zoomIn(tabId)
    const level = await api.tab.getZoomLevel(tabId)
    zoomLevels.value.set(tabId, level)
  }

  /** 缩小页面 */
  async function zoomOut(tabId: string) {
    await api.tab.zoomOut(tabId)
    const level = await api.tab.getZoomLevel(tabId)
    zoomLevels.value.set(tabId, level)
  }

  /** 重置页面缩放 */
  async function zoomReset(tabId: string) {
    await api.tab.zoomReset(tabId)
    const level = await api.tab.getZoomLevel(tabId)
    zoomLevels.value.set(tabId, level)
  }

  /** 获取当前标签页缩放级别 */
  async function fetchZoomLevel(tabId: string) {
    const level = await api.tab.getZoomLevel(tabId)
    zoomLevels.value.set(tabId, level)
  }

  async function detectProxy(tabId: string) {
    return await api.tab.detectProxy(tabId)
  }

  async function setProxyEnabled(tabId: string, enabled: boolean) {
    return await api.tab.setProxyEnabled(tabId, enabled)
  }

  async function applyProxy(tabId: string, proxyId: string | null) {
    return await api.tab.applyProxy(tabId, proxyId)
  }

  async function openDevTools(tabId: string) {
    await api.tab.openDevTools(tabId)
  }

  async function openInNewWindow(tabId: string) {
    await api.tab.openInNewWindow(tabId)
    await closeTab(tabId)
  }

  async function openInBrowser(tabId: string) {
    await api.tab.openInBrowser(tabId)
  }

  /** 切换标签静音状态 */
  async function toggleMute(tabId: string) {
    const tab = tabs.value.find((t) => t.id === tabId)
    if (!tab) return
    const muted = !tab.muted
    tab.muted = muted
    await api.tab.setMuted(tabId, muted)
  }

  /** 静音指定网站（添加到静音列表） */
  async function muteSite(hostname: string) {
    await api.mutedSites.add(hostname)
    mutedSites.value = await api.mutedSites.list()
  }

  /** 取消静音指定网站（从静音列表移除） */
  async function unmuteSite(hostname: string) {
    await api.mutedSites.remove(hostname)
    mutedSites.value = await api.mutedSites.list()
  }

  /** 判断域名是否在静音列表中（支持子域名匹配） */
  function isSiteMuted(hostname: string): boolean {
    return mutedSites.value.some((site) => hostname === site || hostname.endsWith(`.${site}`))
  }

  /** 切换标签固定状态 */
  async function togglePin(tabId: string) {
    const tab = tabs.value.find((t) => t.id === tabId)
    if (!tab) return
    const pinned = !tab.pinned
    await updateTab(tabId, { pinned })
  }

  /** 恢复最近关闭的标签页（Ctrl+Shift+T） */
  async function restoreTab(): Promise<boolean> {
    if (recentlyClosedTabs.value.length === 0) return false

    const snapshot = recentlyClosedTabs.value.shift()!
    // 验证 pageId 对应的 page 是否仍然存在
    const pageStore = usePageStore()
    const page = pageStore.getPage(snapshot.pageId)
    if (!page) return false

    await createTab(snapshot.pageId)
    return true
  }

  /** 跳转到指定序号的标签页（Ctrl+1~8），index 从 1 开始 */
  function gotoTab(index: number): boolean {
    const currentTabs = workspaceTabs.value
    if (currentTabs.length === 0) return false

    const targetIndex = Math.min(index - 1, currentTabs.length - 1)
    const targetTab = currentTabs[targetIndex]
    if (targetTab) {
      switchTab(targetTab.id)
      return true
    }
    return false
  }

  /** 跳转到最后一个标签页（Ctrl+9） */
  function gotoLastTab(): boolean {
    const currentTabs = workspaceTabs.value
    if (currentTabs.length === 0) return false

    const lastTab = currentTabs[currentTabs.length - 1]
    if (lastTab) {
      switchTab(lastTab.id)
      return true
    }
    return false
  }

  /** 注册主进程 → 渲染进程事件监听 */
  function setupListeners() {
    if (listenersReady) return
    listenersReady = true

    api.on('tab:created', (tab: unknown) => {
      const nextTab = tab as Tab
      if (!tabs.value.some((item) => item.id === nextTab.id)) {
        tabs.value.push(nextTab)
        // 新建标签恢复静音状态（账号被静音时新建的标签自动静音）
        if (nextTab.muted) {
          api.tab.setMuted(nextTab.id, true)
        }
      }
    })

    api.on('tab:removed', async (tabId: unknown) => {
      const id = tabId as string
      const wasActive = activeTabId.value === id
      const currentWorkspaceTabs = workspaceTabs.value
      const currentIndex = currentWorkspaceTabs.findIndex((t) => t.id === id)
      const nextWorkspaceTabId = currentIndex === -1
        ? null
        : currentWorkspaceTabs[currentIndex + 1]?.id ?? currentWorkspaceTabs[currentIndex - 1]?.id ?? null

      tabs.value = tabs.value.filter((t) => t.id !== id)
      navStates.value.delete(id)
      favicons.value.delete(id)
      proxyInfos.value.delete(id)

      // 清理嗅探器数据
      useSnifferStore().onTabClosed(id)

      // Notify split store
      const { useSplitStore } = await import('./split')
      const splitStore = useSplitStore()
      splitStore.handleTabClosed(id)

      if (wasActive && splitStore.isSplitActive) {
        const nextSplitTabId = splitStore.focusedPane?.activeTabId
          ?? splitStore.activePanes.find((pane) => pane.activeTabId)?.activeTabId
          ?? null

        if (nextSplitTabId && workspaceTabs.value.some((t) => t.id === nextSplitTabId)) {
          await switchTab(nextSplitTabId)
        } else {
          activeTabId.value = null
          await api.tab.switch('')
        }
        return
      }

      // 自动激活同工作区内的相邻标签页
      if (wasActive) {
        if (nextWorkspaceTabId && workspaceTabs.value.some((t) => t.id === nextWorkspaceTabId)) {
          await switchTab(nextWorkspaceTabId)
        } else {
          activeTabId.value = null
          await api.tab.switch('')
        }
      }
    })

    api.on('tab:activated', (tabId: unknown) => {
      activeTabId.value = tabId as string
      fetchZoomLevel(tabId as string)
    })

    // 插件设置的分组过滤
    api.on('tab:set-group-filter', (groupId: unknown) => {
      tabGroupFilterId.value = groupId as string | null
    })

    api.on('tab:title-updated', (tabId: unknown, title: unknown) => {
      const t = tabs.value.find((t) => t.id === tabId)
      if (t) {
        t.title = title as string
        // 实时持久化标题到主进程 store，避免 beforeunload 时 IPC 未完成导致标题丢失
        api.tab.update(tabId, { title: title as string })
        // 更新历史记录中对应 URL 的标题
        const historyStore = useHistoryStore()
        historyStore.updateTitle(t.url, title as string)
      }
    })

    api.on('tab:url-updated', (tabId: unknown, url: unknown) => {
      const t = tabs.value.find((t) => t.id === tabId)
      if (t) {
        t.url = url as string
        // 实时持久化 URL 到主进程 store
        api.tab.update(tabId, { url: url as string })
        // 记录浏览历史（仅 http/https）
        const historyStore = useHistoryStore()
        historyStore.addHistory(url as string, t.title)
      }
    })

    api.on('tab:nav-state', (tabId: unknown, state: unknown) => {
      navStates.value.set(tabId as string, state as NavState)
    })

    api.on('tab:proxy-info', (tabId: unknown, info: unknown) => {
      const id = tabId as string
      if (!info) {
        proxyInfos.value.delete(id)
        return
      }

      proxyInfos.value.set(id, info as TabProxyInfo)
    })

    api.on('tab:favicon-updated', (tabId: unknown, url: unknown) => {
      const faviconUrl = url as string
      favicons.value.set(tabId as string, faviconUrl)
      // 从 site-icon:// URL 中提取 domain，更新版本号强制其他组件刷新
      if (faviconUrl.startsWith('site-icon://')) {
        const domain = faviconUrl.replace('site-icon://', '').split('?')[0]
        const cur = faviconVersions.value.get(domain) || 0
        faviconVersions.value.set(domain, cur + 1)
      }
    })

    // 新窗口打开 → 在新 tab 中加载
    api.on('tab:open-url', async (pageId: unknown, url: unknown) => {
      await createTabWithUrl(pageId as string, url as string)
    })

    // 标签冻结/解冻状态
    api.on('tab:frozen', (tabId: unknown, frozen: unknown) => {
      const id = tabId as string
      if (frozen) {
        frozenTabIds.value.add(id)
      } else {
        frozenTabIds.value.delete(id)
      }
    })

    // 自动静音匹配（导航到静音网站时触发）
    api.on('tab:auto-muted', (tabId: unknown) => {
      const t = tabs.value.find((t) => t.id === (tabId as string))
      if (t) t.muted = true
    })

    // 深度链接 → 激活或创建对应页面的 tab
    api.on('open-page', async (pageId: unknown) => {
      const id = pageId as string
      const pageTabs = sortedTabs.value.filter((t) => t.pageId === id)
      if (pageTabs.length > 0) {
        await switchTab(pageTabs[pageTabs.length - 1].id)
      } else {
        await createTab(id)
      }
    })

    // Tray 菜单打开页面
    api.on('tray:openInApp', async (pageId: unknown) => {
      const id = pageId as string
      const existingTab = sortedTabs.value.find(t => t.pageId === id)
      if (existingTab) {
        await switchTab(existingTab.id)
      } else {
        await createTab(id)
      }
    })

    // 外部链接 → 使用默认容器在当前工作区打开新 tab
    api.on('open-external-url', async (url: unknown) => {
      const externalUrl = url as string
      const containerStore = useContainerStore()

      if (containerStore.askContainerOnOpen) {
        // 开启"每次询问"：弹出容器选择对话框
        pendingExternalUrl.value = externalUrl
        return
      }

      // 未开启询问：使用默认容器和工作区打开，不持久化 Page
      await openExternalUrlInContainer(externalUrl, containerStore.defaultContainerId, containerStore.defaultWorkspaceId)
    })
  }

  /** 初始化 */
  async function init() {
    await loadTabs()
    mutedSites.value = await api.mutedSites.list()
    setupListeners()

    if (restoreReady) return

    // 恢复保存的 tab（重建 WebContentsView）
    if (tabs.value.length > 0) {
      await api.tab.restoreAll()
      // 优先恢复上次激活的 tab，否则回退到第一个
      const savedActiveId = localStorage.getItem(ACTIVE_TAB_KEY)
      const targetTab = savedActiveId
        ? workspaceTabs.value.find((t) => t.id === savedActiveId)
        : null

      if (targetTab) {
        await switchTab(targetTab.id)
      } else if (workspaceTabs.value.length > 0) {
        await switchTab(workspaceTabs.value[0].id)
      } else {
        activeTabId.value = null
        await api.tab.switch('')
      }
    }

    restoreReady = true
  }

  // 激活标签变化时持久化，以便重启后恢复
  watch(activeTabId, (id) => {
    if (id) localStorage.setItem(ACTIVE_TAB_KEY, id)
  })

  // 工作区切换时，自动激活当前工作区内的 tab
  watch(() => {
    const workspaceStore = useWorkspaceStore()
    return workspaceStore.activeWorkspaceId
  }, () => {
    // tabs 未加载完成时跳过（初始化期间的 workspace 恢复由 tabStore.init() 处理）
    if (tabs.value.length === 0) return

    const inWorkspace = workspaceTabs.value.some((t) => t.id === activeTabId.value)
    if (inWorkspace) return
    if (workspaceTabs.value.length > 0) {
      switchTab(workspaceTabs.value[0].id)
    } else {
      activeTabId.value = null
      api.tab.switch('')
    }
  })

  /** 使用指定容器打开外部 URL（不持久化 Page，无分组归属） */
  async function openExternalUrlInContainer(url: string, containerId: string, workspaceId?: string) {
    const workspaceStore = useWorkspaceStore()
    const containerStore = useContainerStore()
    const targetWorkspaceId = workspaceId === '__active__' || !workspaceId
      ? workspaceStore.activeWorkspaceId
      : workspaceId

    // 切换到目标工作区
    if (targetWorkspaceId !== workspaceStore.activeWorkspaceId) {
      workspaceStore.activate(targetWorkspaceId)
      await nextTick()
    }

    // 无 pageId 模式：直接指定 containerId + workspaceId，不关联任何分组
    const resolvedContainerId = containerId || containerStore.defaultContainerId
    const tab = await api.tab.create(null, url, resolvedContainerId, targetWorkspaceId)
    await nextTick()
    await activateCreatedTab(tab.id)
  }

  /** 取消待处理的外部 URL */
  function cancelExternalUrl() {
    pendingExternalUrl.value = null
  }

  /** 保存当前所有 tab 状态到主进程（退出前调用） */
  async function saveState() {
    await api.tab.saveAll(tabs.value)
  }

  return {
    tabs,
    activeTabId,
    tabGroupFilterId,
    navStates,
    favicons,
    faviconVersions,
    frozenTabIds,
    sortedTabs,
    workspaceTabs,
    groupedWorkspaceTabs,
    activeTab,
    activeNavState,
    activeProxyInfo,
    isInternalPage,
    internalPagePath,
    tabLayout,
    toggleLayout,
    bookmarkBarVisible,
    toggleBookmarkBar,
    tabGroupEnabled,
    tabGroupMode,
    setTabGroupMode,
    setTabGroupFilter,
    clearTabGroupFilter,
    groupedSortedTabs,
    loadTabs,
    createTab,
    createTabForSite,
    closeTab,
    switchTab,
    updateTab,
    reorderTabs,
    navigate,
    openInternalPage,
    goBack,
    goForward,
    reload,
    forceReload,
    zoomIn,
    zoomOut,
    zoomReset,
    zoomLevels,
    fetchZoomLevel,
    activeZoomLevel,
    detectProxy,
    setProxyEnabled,
    applyProxy,
    openDevTools,
    openInNewWindow,
    openInBrowser,
    toggleMute,
    muteSite,
    unmuteSite,
    mutedSites,
    isSiteMuted,
    togglePin,
    restoreTab,
    gotoTab,
    gotoLastTab,
    pendingExternalUrl,
    openExternalUrlInContainer,
    cancelExternalUrl,
    init,
    saveState
  }
})

import { defineStore } from 'pinia'
import { ref, computed, watch } from 'vue'
import type { Workflow, WorkflowFolder, WorkflowNode, ExecutionLog } from '@/lib/workflow/types'
import { WorkflowEngine, type EngineStatus } from '@/lib/workflow/engine'
import { executeRendererWorkflowTool } from '@/lib/agent/workflow-renderer-tools'
import type { WorkflowToolExecuteRequest } from '../../preload'

const DRAFT_KEY = 'workflow-draft'

export interface WorkflowChanges {
  upsertNodes: any[]
  deleteNodeIds: string[]
  upsertEdges: any[]
  deleteEdgeIds: string[]
}

export const useWorkflowStore = defineStore('workflow', () => {
  const api = () => (window as any).api

  // ====== 数据 ======
  const workflows = ref<Workflow[]>([])
  const workflowFolders = ref<WorkflowFolder[]>([])
  const currentWorkflow = ref<Workflow | null>(null)
  const selectedNodeId = ref<string | null>(null)

  // ====== 执行状态 ======
  const executionStatus = ref<EngineStatus>('idle')
  const executionLog = ref<ExecutionLog | null>(null)
  const executionContext = ref<Record<string, any>>({})
  const engine = ref<WorkflowEngine | null>(null)

  // ====== 执行历史 ======
  const executionLogs = ref<ExecutionLog[]>([])
  const selectedExecutionLogId = ref<string | null>(null)

  // ====== 单节点调试 ======
  const debugNodeStatus = ref<'idle' | 'running' | 'completed' | 'error'>('idle')
  const debugNodeResult = ref<{
    status: 'completed' | 'error'
    output?: any
    error?: string
    duration: number
  } | null>(null)
  const debugNodeId = ref<string | null>(null)

  // ====== Undo/Redo ======
  const MAX_HISTORY = 1000
  const undoStack = ref<string[]>([])
  const redoStack = ref<string[]>([])
  const operationLog = ref<{ description: string; timestamp: number }[]>([])

  function captureSnapshot(): string {
    if (!currentWorkflow.value) return ''
    return JSON.stringify({ nodes: currentWorkflow.value.nodes, edges: currentWorkflow.value.edges })
  }

  function applySnapshot(snapshot: string): void {
    if (!currentWorkflow.value || !snapshot) return
    const parsed = JSON.parse(snapshot)
    currentWorkflow.value.nodes = parsed.nodes
    currentWorkflow.value.edges = parsed.edges
  }

  function pushUndo(description: string): void {
    const snapshot = captureSnapshot()
    if (!snapshot) return
    undoStack.value.push(snapshot)
    if (undoStack.value.length > MAX_HISTORY) undoStack.value.shift()
    redoStack.value = []
    operationLog.value.unshift({ description, timestamp: Date.now() })
    if (operationLog.value.length > MAX_HISTORY) operationLog.value.length = MAX_HISTORY
  }

  function undo(): void {
    if (undoStack.value.length === 0) return
    const current = captureSnapshot()
    const prev = undoStack.value.pop()!
    redoStack.value.push(current)
    applySnapshot(prev)
    operationLog.value.unshift({ description: '撤销操作', timestamp: Date.now() })
    if (operationLog.value.length > MAX_HISTORY) operationLog.value.length = MAX_HISTORY
  }

  function redo(): void {
    if (redoStack.value.length === 0) return
    const current = captureSnapshot()
    const next = redoStack.value.pop()!
    undoStack.value.push(current)
    applySnapshot(next)
    operationLog.value.unshift({ description: '重做操作', timestamp: Date.now() })
    if (operationLog.value.length > MAX_HISTORY) operationLog.value.length = MAX_HISTORY
  }

  const canUndo = computed(() => undoStack.value.length > 0)
  const canRedo = computed(() => redoStack.value.length > 0)

  // ====== 计算属性 ======
  const rootFolders = computed(() =>
    workflowFolders.value
      .filter((f) => f.parentId === null)
      .sort((a, b) => a.order - b.order),
  )

  const selectedNode = computed(() => {
    if (!selectedNodeId.value || !currentWorkflow.value) return null
    return currentWorkflow.value.nodes.find((n) => n.id === selectedNodeId.value) || null
  })

  const selectedExecutionLog = computed<ExecutionLog | null>(() => {
    const id = selectedExecutionLogId.value
    if (!id) return executionLog.value
    return executionLogs.value.find((l) => l.id === id) || executionLog.value
  })

  /** 执行前验证：检查开始/结束节点存在且连通 */
  const executionValidationError = computed<string | null>(() => {
    if (!currentWorkflow.value) return '未加载工作流'

    const nodes = currentWorkflow.value.nodes
    const startNodes = nodes.filter((n) => n.type === 'start')
    const endNodes = nodes.filter((n) => n.type === 'end')

    if (startNodes.length === 0) return '缺少「开始」节点'
    if (endNodes.length === 0) return '缺少「结束」节点'
    if (startNodes.length > 1) return '只能有一个「开始」节点'
    if (endNodes.length > 1) return '只能有一个「结束」节点'

    // BFS 检查从开始节点是否能到达结束节点
    const edges = currentWorkflow.value.edges
    const visited = new Set<string>()
    const queue = [startNodes[0].id]
    visited.add(startNodes[0].id)

    while (queue.length > 0) {
      const current = queue.shift()!
      for (const edge of edges) {
        if (edge.source === current && !visited.has(edge.target)) {
          visited.add(edge.target)
          queue.push(edge.target)
        }
      }
    }

    if (!visited.has(endNodes[0].id)) return '「开始」与「结束」节点未连通'

    return null
  })

  // ====== 执行历史管理 ======
  async function loadExecutionLogs(): Promise<void> {
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) {
      executionLogs.value = []
      return
    }
    executionLogs.value = await api().executionLog.list(workflowId)
    if (selectedExecutionLogId.value && !executionLogs.value.find((l) => l.id === selectedExecutionLogId.value)) {
      selectedExecutionLogId.value = null
    }
  }

  async function deleteExecutionLog(logId: string): Promise<void> {
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) return
    await api().executionLog.delete(workflowId, logId)
    executionLogs.value = executionLogs.value.filter((l) => l.id !== logId)
    if (selectedExecutionLogId.value === logId) selectedExecutionLogId.value = null
  }

  async function clearExecutionLogs(): Promise<void> {
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) return
    await api().executionLog.clear(workflowId)
    executionLogs.value = []
    selectedExecutionLogId.value = null
  }

  async function saveCurrentExecutionLog(): Promise<void> {
    const log = executionLog.value
    if (!log || log.status === 'running' || log.status === 'paused') return
    if (!log.id) log.id = `exec-${Date.now()}`
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) return
    log.workflowId = workflowId
    await api().executionLog.save(workflowId, log)
  }

  // 切换工作流时加载历史
  watch(() => currentWorkflow.value?.id, () => {
    loadExecutionLogs()
  })

  // ====== 数据 CRUD ======
  async function loadData() {
    workflows.value = await api().workflow.list()
    workflowFolders.value = await api().workflowFolder.list()
  }

  async function saveWorkflow(workflow: Workflow): Promise<void> {
    const plain = JSON.parse(JSON.stringify(workflow)) as Workflow
    const existing = workflows.value.find((w) => w.id === plain.id)
    const now = Date.now()
    if (existing) {
      await api().workflow.update(plain.id, { ...plain, updatedAt: now })
      Object.assign(existing, { ...plain, updatedAt: now })
    } else {
      const created = await api().workflow.create({ ...plain, createdAt: now, updatedAt: now })
      workflows.value.push(created)
      currentWorkflow.value = created
    }
    clearDraft()
    // 保存时自动创建版本快照
    await saveVersion()
  }

  async function deleteWorkflow(id: string): Promise<void> {
    await api().workflow.delete(id)
    workflows.value = workflows.value.filter((w) => w.id !== id)
    if (currentWorkflow.value?.id === id) {
      currentWorkflow.value = null
      clearDraft()
    }
  }

  async function createFolder(name: string, parentId: string | null = null): Promise<void> {
    const folder = await api().workflowFolder.create({
      name,
      parentId,
      order: workflowFolders.value.filter((f) => f.parentId === parentId).length,
      createdAt: Date.now(),
    })
    workflowFolders.value.push(folder)
  }

  async function deleteFolder(id: string): Promise<void> {
    await api().workflowFolder.delete(id)
    workflowFolders.value = workflowFolders.value.filter((f) => f.id !== id)
  }

  async function updateFolder(id: string, data: Partial<WorkflowFolder>): Promise<void> {
    await api().workflowFolder.update(id, data)
    const idx = workflowFolders.value.findIndex((f) => f.id === id)
    if (idx !== -1) Object.assign(workflowFolders.value[idx], data)
  }

  // ====== 编辑操作 ======
  function newWorkflow(folderId: string | null = null) {
    const startNodeId = crypto.randomUUID()
    const endNodeId = crypto.randomUUID()
    currentWorkflow.value = {
      id: crypto.randomUUID(),
      name: '未命名工作流',
      folderId,
      nodes: [
        { id: startNodeId, type: 'start', label: '开始', position: { x: 100, y: 250 }, data: {} },
        { id: endNodeId, type: 'end', label: '结束', position: { x: 600, y: 250 }, data: {} },
      ],
      edges: [],
      createdAt: Date.now(),
      updatedAt: Date.now(),
    }
    selectedNodeId.value = null
    executionStatus.value = 'idle'
    executionLog.value = null
    executionContext.value = {}
    saveDraft()
  }

  function addNode(type: string, position: { x: number; y: number }): WorkflowNode {
    pushUndo(`添加节点: ${type}`)
    const node: WorkflowNode = {
      id: crypto.randomUUID(),
      type,
      label: type,
      position,
      data: {},
    }
    currentWorkflow.value!.nodes.push(node)
    return node
  }

  function removeNode(nodeId: string): void {
    if (!currentWorkflow.value) return
    pushUndo('删除节点')
    currentWorkflow.value.nodes = currentWorkflow.value.nodes.filter((n) => n.id !== nodeId)
    currentWorkflow.value.edges = currentWorkflow.value.edges.filter(
      (e) => e.source !== nodeId && e.target !== nodeId,
    )
    if (selectedNodeId.value === nodeId) selectedNodeId.value = null
  }

  function cloneNode(nodeId: string): WorkflowNode | null {
    if (!currentWorkflow.value) return null
    pushUndo('克隆节点')
    const source = currentWorkflow.value.nodes.find((n) => n.id === nodeId)
    if (!source) return null
    const cloned: WorkflowNode = {
      id: crypto.randomUUID(),
      type: source.type,
      label: source.label,
      position: { x: source.position.x + 30, y: source.position.y + 30 },
      data: JSON.parse(JSON.stringify(source.data)),
    }
    currentWorkflow.value.nodes.push(cloned)
    return cloned
  }

  function updateNodeData(nodeId: string, data: Record<string, any>): void {
    pushUndo('修改节点属性')
    const node = currentWorkflow.value?.nodes.find((n) => n.id === nodeId)
    if (node) node.data = { ...node.data, ...data }
  }

  function updateNodePosition(nodeId: string, position: { x: number; y: number }): void {
    const node = currentWorkflow.value?.nodes.find((n) => n.id === nodeId)
    if (node) node.position = position
  }

  function updateNodeLabel(nodeId: string, label: string): void {
    pushUndo('修改节点标签')
    const node = currentWorkflow.value?.nodes.find((n) => n.id === nodeId)
    if (node) node.label = label
  }

  function updateNodeState(nodeId: string, nodeState: import('@/lib/workflow/types').NodeRunState): void {
    pushUndo('修改节点状态')
    const node = currentWorkflow.value?.nodes.find((n) => n.id === nodeId)
    if (node) node.nodeState = nodeState
  }

  function addEdge(
    source: string,
    target: string,
    sourceHandle: string | null = null,
    targetHandle: string | null = null,
  ): void {
    if (!currentWorkflow.value) return

    if (
      currentWorkflow.value.edges.some(
        (e) =>
          e.source === source
          && e.target === target
          && (e.sourceHandle ?? null) === sourceHandle
          && (e.targetHandle ?? null) === targetHandle,
      )
    ) {
      return
    }

    pushUndo('添加连线')

    currentWorkflow.value.edges.push({
      id: `e-${source}-${sourceHandle ?? 'default'}-${target}-${targetHandle ?? 'default'}`,
      source,
      target,
      sourceHandle,
      targetHandle,
    })
  }

  function removeEdge(edgeId: string): void {
    if (!currentWorkflow.value) return
    pushUndo('删除连线')
    currentWorkflow.value.edges = currentWorkflow.value.edges.filter((e) => e.id !== edgeId)
  }

  // ====== 执行控制 ======
  async function startExecution(): Promise<void> {
    if (!currentWorkflow.value) return
    executionStatus.value = 'running'
    executionLog.value = null
    executionContext.value = {}

    engine.value = new WorkflowEngine(
      currentWorkflow.value.nodes,
      currentWorkflow.value.edges,
      {
        onLogUpdate: (log) => {
          executionLog.value = { ...log }
        },
        onNodeStatusChange: () => {},
      },
    )

    const log = await engine.value.start()
    executionStatus.value = engine.value.status as EngineStatus
    executionContext.value = engine.value.currentContext
    executionLog.value = log

    if (log.status === 'completed' || log.status === 'error') {
      log.id = `exec-${Date.now()}`
      log.workflowId = currentWorkflow.value.id
      executionLogs.value.unshift(log)
      if (executionLogs.value.length > 50) executionLogs.value.length = 50
      selectedExecutionLogId.value = log.id
      saveExecutionLogToDisk(log)
    }
  }

  async function saveExecutionLogToDisk(log: ExecutionLog): Promise<void> {
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) return
    try {
      await api().executionLog.save(workflowId, log)
    } catch { /* ignore */ }
  }

  function pauseExecution(): void {
    engine.value?.pause()
  }

  async function resumeExecution(): Promise<void> {
    if (!engine.value) return
    const log = await engine.value.resume()
    executionStatus.value = engine.value.status as EngineStatus
    executionContext.value = engine.value.currentContext
    executionLog.value = log

    if (log.status === 'completed' || log.status === 'error') {
      log.id = `exec-${Date.now()}`
      log.workflowId = currentWorkflow.value!.id
      executionLogs.value.unshift(log)
      if (executionLogs.value.length > 50) executionLogs.value.length = 50
      selectedExecutionLogId.value = log.id
      saveExecutionLogToDisk(log)
    }
  }

  function stopExecution(): void {
    engine.value?.stop()
  }

  // ====== 单节点调试 ======
  async function debugSingleNode(nodeId: string): Promise<void> {
    if (!currentWorkflow.value) return
    const node = currentWorkflow.value.nodes.find((n) => n.id === nodeId)
    if (!node) return

    debugNodeStatus.value = 'running'
    debugNodeResult.value = null
    debugNodeId.value = nodeId

    const tempEngine = new WorkflowEngine([node], [])
    const result = await tempEngine.debugSingleNode(node, executionContext.value)

    debugNodeResult.value = result
    debugNodeStatus.value = result.status
  }

  // ====== 版本管理 ======
  const versions = ref<any[]>([])

  async function loadVersions(): Promise<void> {
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) { versions.value = []; return }
    versions.value = await api().workflowVersion.list(workflowId)
  }

  async function saveVersion(name?: string): Promise<void> {
    const wf = currentWorkflow.value
    if (!wf) return
    const versionName = name || await api().workflowVersion.nextName(wf.id)
    const plainNodes = JSON.parse(JSON.stringify(wf.nodes))
    const plainEdges = JSON.parse(JSON.stringify(wf.edges))
    const version = await api().workflowVersion.add(wf.id, versionName, plainNodes, plainEdges)
    versions.value.unshift(version)
  }

  async function deleteVersion(versionId: string): Promise<void> {
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) return
    await api().workflowVersion.delete(workflowId, versionId)
    versions.value = versions.value.filter((v) => v.id !== versionId)
  }

  async function restoreVersion(versionId: string): Promise<void> {
    const workflowId = currentWorkflow.value?.id
    if (!workflowId) return
    const version = await api().workflowVersion.get(workflowId, versionId)
    if (!version) return
    pushUndo('恢复版本')
    currentWorkflow.value!.nodes = JSON.parse(JSON.stringify(version.snapshot.nodes))
    currentWorkflow.value!.edges = JSON.parse(JSON.stringify(version.snapshot.edges))
  }

  // 切换工作流时加载版本并清空 undo/redo
  watch(() => currentWorkflow.value?.id, () => {
    loadVersions()
    undoStack.value = []
    redoStack.value = []
    operationLog.value = []
  })

  // ====== 草稿持久化 ======
  function saveDraft(): void {
    if (!currentWorkflow.value) return
    try {
      localStorage.setItem(DRAFT_KEY, JSON.stringify(currentWorkflow.value))
    } catch { /* quota exceeded, ignore */ }
  }

  function restoreDraft(): boolean {
    try {
      const raw = localStorage.getItem(DRAFT_KEY)
      if (!raw) return false
      const draft = JSON.parse(raw) as Workflow
      if (!draft?.id) return false
      currentWorkflow.value = draft
      selectedNodeId.value = null
      executionStatus.value = 'idle'
      executionLog.value = null
      executionContext.value = {}
      return true
    } catch {
      return false
    }
  }

  function clearDraft(): void {
    localStorage.removeItem(DRAFT_KEY)
  }

  // ====== AI 助手增量更新 ======

  function summarizeChanges(changes: WorkflowChanges): string {
    const parts: string[] = []
    if (changes.upsertNodes.length) parts.push(`+${changes.upsertNodes.length}节点`)
    if (changes.deleteNodeIds.length) parts.push(`-${changes.deleteNodeIds.length}节点`)
    if (changes.upsertEdges.length) parts.push(`+${changes.upsertEdges.length}连线`)
    if (changes.deleteEdgeIds.length) parts.push(`-${changes.deleteEdgeIds.length}连线`)
    return parts.join(' ') || '无变更'
  }

  function mergeWorkflowChanges(changes: WorkflowChanges) {
    if (!currentWorkflow.value) return

    // 记录到 undo 栈
    pushUndo('AI 修改: ' + summarizeChanges(changes))

    // 增量更新节点
    for (const node of changes.upsertNodes) {
      const idx = currentWorkflow.value.nodes.findIndex(n => n.id === node.id)
      if (idx >= 0) {
        currentWorkflow.value.nodes[idx] = node
      } else {
        currentWorkflow.value.nodes.push(node)
      }
    }

    // 删除节点
    if (changes.deleteNodeIds.length > 0) {
      currentWorkflow.value.nodes = currentWorkflow.value.nodes
        .filter(n => !changes.deleteNodeIds.includes(n.id))
    }

    // 增量更新边
    for (const edge of changes.upsertEdges) {
      const idx = currentWorkflow.value.edges.findIndex(e => e.id === edge.id)
      if (idx >= 0) {
        currentWorkflow.value.edges[idx] = edge
      } else {
        currentWorkflow.value.edges.push(edge)
      }
    }

    // 删除边
    if (changes.deleteEdgeIds.length > 0) {
      currentWorkflow.value.edges = currentWorkflow.value.edges
        .filter(e => !changes.deleteEdgeIds.includes(e.id))
    }
  }

  function listenForFileUpdates() {
    const cleanup = (window as any).api.on('workflow:updated', (data: any) => {
      if (data.workflowId === currentWorkflow.value?.id && data.changes) {
        mergeWorkflowChanges(data.changes)
      }
    })
    return cleanup
  }

  function listenForWorkflowToolRequests() {
    const cleanup = (window as any).api.on('workflow-tool:execute', async (request: WorkflowToolExecuteRequest) => {
      const result = await executeRendererWorkflowTool(request.name, request.args || {})

      try {
        await (window as any).api.workflowTool.respond(request.requestId, result)
      } catch (error) {
        console.error('[workflow-store] failed to respond workflow tool request', error)
      }
    })

    return cleanup
  }

  return {
    // 数据
    workflows,
    workflowFolders,
    currentWorkflow,
    selectedNodeId,
    // 计算属性
    rootFolders,
    selectedNode,
    executionValidationError,
    // 执行状态
    executionStatus,
    executionLog,
    executionContext,
    // 执行历史
    executionLogs,
    selectedExecutionLogId,
    selectedExecutionLog,
    loadExecutionLogs,
    deleteExecutionLog,
    clearExecutionLogs,
    // CRUD
    loadData,
    saveWorkflow,
    deleteWorkflow,
    createFolder,
    deleteFolder,
    updateFolder,
    // 编辑
    newWorkflow,
    addNode,
    removeNode,
    cloneNode,
    updateNodeData,
    updateNodePosition,
    updateNodeLabel,
    updateNodeState,
    addEdge,
    removeEdge,
    // 执行
    startExecution,
    pauseExecution,
    resumeExecution,
    stopExecution,
    // 单节点调试
    debugNodeStatus,
    debugNodeResult,
    debugNodeId,
    debugSingleNode,
    // Undo/Redo
    undo,
    redo,
    canUndo,
    canRedo,
    undoStack,
    redoStack,
    operationLog,
    // 版本管理
    versions,
    loadVersions,
    saveVersion,
    deleteVersion,
    restoreVersion,
    // 草稿
    saveDraft,
    restoreDraft,
    clearDraft,
    // AI 助手增量更新
    mergeWorkflowChanges,
    listenForFileUpdates,
    listenForWorkflowToolRequests,
  }
})
